    }
    // v5.14: Deferred cooldown — set immediately only when market is open.
    // When market is closed (GTC order), store as pending and confirm at market open.
    if (!state._reEntryCooldown) state._reEntryCooldown = {};
    if (!state._pendingGTCCloses) state._pendingGTCCloses = {};

    if (_marketIsOpen) {
      // Position fills immediately — set cooldown now
      state._reEntryCooldown[ticker] = _tkNow2;
      console.log('[RE-ENTRY v5.14] Cooldown set immediately (market open, filled now) for ' + ticker);
    } else {
      // GTC order placed — cooldown deferred until position confirmed flat at market open
      state._pendingGTCCloses[ticker] = {
        submittedAt:  _tkNow2,
        triggerType:  _tkTriggerType,
        triggerData:  _tkTriggerData,
        retryCount:   0,
        notified:     false
      };
      console.log('[GTC-PENDING v5.14] Stored pending close for ' + ticker + ' — cooldown deferred until 9:40 AM ET re-check');
    }
    state.weeklyKillStats.lastKill = {
      ticker, triggerType: _tkTriggerType, reason: _tkInternalReason,
      closed: _tkClosed, ts: new Date(_tkNow2).toISOString()
    };
    console.log('[KILL-STATS] Week ' + state.weeklyKillStats.weekStarting + ': ' +
      JSON.stringify(state.weeklyKillStats.killsByReason) + ' | Total: ' + state.weeklyKillStats.totalKills);

    // ── RETURN ────────────────────────────────────────────────────
    return [{
      json: {
        ...d,
        _sm_action:        'TICKER_KILLED',
        _sm_route:         'SKIP',
        _sm_reason:        'Per-ticker kill v5.10 (' + _tkTriggerType + '): ' + _tkInternalReason,
        _sm_version:       'v5.10',
        _sm_is_heartbeat:  'false',
        _tk_closed:        _tkClosed,
        _tk_trigger_type:  _tkTriggerType,
        _tk_channel_reason: _tkSanitized.reason,
        _tk_weekly_kills:  state.weeklyKillStats.totalKills,
        ticker, timeframe
      }
    }];
  }
}
// ── END v5.10 PER-TICKER KILL TRIGGER ──────────────────────────

// ── 1. Deduplication — Enhanced for heartbeats ────────────────
const dedupKey = `${ticker}_${timeframe || 'UNK'}`;
// ============================================================
// v5.3: MARKET HOURS + WEEKEND AWARENESS
// ============================================================
const nowDate = new Date(now);
const nowHourET = parseInt(nowDate.toLocaleString('en-US', { timeZone: 'America/New_York', hour: 'numeric', hour12: false }));
const nowMinET = parseInt(nowDate.toLocaleString('en-US', { timeZone: 'America/New_York', minute: 'numeric' }));
const nowDayOfWeek = parseInt(nowDate.toLocaleString('en-US', { timeZone: 'America/New_York', weekday: 'short' }) === 'Sun' ? 0 : nowDate.toLocaleString('en-US', { timeZone: 'America/New_York', weekday: 'short' }) === 'Sat' ? 6 : nowDate.getDay());
const isWeekendET = (nowDayOfWeek === 0 || nowDayOfWeek === 6);
const marketTimeMinutes = nowHourET * 60 + nowMinET;
const isPreMarket = marketTimeMinutes >= 420 && marketTimeMinutes < 570;  // 7:00-9:30 AM ET
const isRegularHours = marketTimeMinutes >= 570 && marketTimeMinutes < 960; // 9:30 AM - 4:00 PM ET
const isAfterHours = marketTimeMinutes >= 960 && marketTimeMinutes < 1200; // 4:00-8:00 PM ET
const isMarketHours = isRegularHours;
const isExtendedHours = isPreMarket || isAfterHours;
const isScalpTimeframe = ['5', '15', '5M', '15M', '1', '1M', '3', '3M'].includes((timeframe || '').toUpperCase());

const prev     = state.signalStates[dedupKey] || null;
const isScalpCooldown = ['5', '15', '5M', '15M', '1', '1M', '3', '3M'].includes((timeframe || '').toUpperCase());
const COOLDOWN_MS = isScalpCooldown ? 5 * 60 * 1000 : 15 * 60 * 1000; // 5min scalp, 15min swing/daily

let dedupAction = 'FORWARD';
let dedupReason = '';
let routeAction = 'FULL';
// v5.6: Track whether this bar was promoted from heartbeat by score
let heartbeatPromoted = false;
let promotionReason   = '';

if (prev) {
  const timeSinceLast = now - prev.timestamp;
  const sameState = prev.execution === execution && prev.signal === signal;

  if (isHeartbeat) {
    if (sameState) {
      // ============================================================
      // v5.6: SCORE-GATED HEARTBEAT PROMOTION
      // Instead of always discarding same-state heartbeats, check
      // the raw score. If it exceeds the threshold, promote to FULL
      // so the VC Gate / Perplexity / Alpaca / Telegram pipeline
      // evaluates this bar. Otherwise, stay SKIP (internal only).
      // ============================================================
      if (rawScore > HEARTBEAT_SCORE_THRESHOLD) {
        dedupAction = 'FORWARD';
        dedupReason = `Heartbeat PROMOTED: ${dedupKey} score ${rawScore} > ${HEARTBEAT_SCORE_THRESHOLD} (same state ${execution}/${signal})`;
        routeAction = 'FULL';
        heartbeatPromoted = true;
        promotionReason = `raw_score ${rawScore} > ${HEARTBEAT_SCORE_THRESHOLD}`;
      } else {
        dedupAction = 'DISCARD';
        dedupReason = `Heartbeat skip: ${dedupKey} still ${execution}/${signal}, score ${rawScore} <= ${HEARTBEAT_SCORE_THRESHOLD} (${Math.round(timeSinceLast / 1000)}s ago)`;
      }
    } else {
      dedupAction = 'FORWARD';
      dedupReason = `Heartbeat state change: ${dedupKey} ${prev.execution}${String.fromCharCode(8594)}${execution}`;
      // v5.2: EXIT signals (→ STAND ASIDE) get FAST_ONLY, entry signals get FULL
      routeAction = (execution === 'STAND ASIDE') ? 'FAST_ONLY' : 'FULL';
    }
  } else {
    // v5.16: Max dedup window — signals older than 4h treated as fresh (pre-market state reset)
    const MAX_DEDUP_MS = 4 * 60 * 60 * 1000; // 4 hours
    if (sameState && timeSinceLast < MAX_DEDUP_MS) {
      dedupAction = 'DISCARD';
      dedupReason = `Duplicate: ${dedupKey} already ${execution}/${signal} (${Math.round(timeSinceLast / 1000)}s ago)`;
    } else if (sameState) {
      // Same state but older than 4h — treat as fresh (session refresh, e.g. pre-market → intraday)
      dedupAction = 'FORWARD';
      dedupReason = `Session refresh: ${dedupKey} ${execution}/${signal} was ${Math.round(timeSinceLast/1000)}s ago (>4h window)`;
      routeAction = 'FULL';
    } else if (timeSinceLast < COOLDOWN_MS && execution !== 'STAND ASIDE') {
      dedupAction = 'DISCARD';
      dedupReason = `Cooldown: ${dedupKey} changed ${prev.execution}${String.fromCharCode(8594)}${execution} but only ${Math.round(timeSinceLast / 1000)}s since last`;
    } else {
      dedupAction = 'FORWARD';
      dedupReason = `State change: ${dedupKey} ${prev.execution}${String.fromCharCode(8594)}${execution}`;
      // v5.2: EXIT signals (→ STAND ASIDE) get FAST_ONLY, entry signals get FULL
      routeAction = (execution === 'STAND ASIDE') ? 'FAST_ONLY' : 'FULL';
    }
  }
} else {
  if (isHeartbeat) {
    dedupAction = 'FORWARD';
    dedupReason = `New ticker heartbeat: ${dedupKey} initial state ${execution}`;
    routeAction = 'FAST_ONLY';
  } else {
    dedupAction = 'FORWARD';
    dedupReason = `New ticker signal: ${dedupKey} initial ${execution}`;
    // v5.2: Only FULL route for actual entries (BUY/SELL), not STAND ASIDE
    routeAction = (execution === 'STAND ASIDE') ? 'FAST_ONLY' : 'FULL';
  }
}

if (dedupAction === 'DISCARD') {
  state.auditLog.push({
    ts: new Date(now).toISOString(), ticker, timeframe,
    execution, signal, action: 'DISCARD', reason: dedupReason,
    isHeartbeat, rawScore
  });
  if (state.auditLog.length > 1000) state.auditLog.splice(0, state.auditLog.length - 750);

  return [{
    json: {
      _sm_action:       'DEDUPLICATED',
      _sm_reason:       dedupReason,
      _sm_route:        'SKIP',
      _sm_is_heartbeat: isHeartbeat,
      _sm_raw_score:    rawScore,
      _sm_version:      'v5.6',
      ticker,
      timeframe,
      signal: direction
    }
  }];
}

// ── 2. VIX Regime Tag ─────────────────────────────────────────
let vixRegime;
if      (vix < 18)  vixRegime = 'LOW';
else if (vix < 25)  vixRegime = 'MEDIUM';
else if (vix < 30)  vixRegime = 'HIGH';
else                vixRegime = 'EXTREME';

// ── 3. Market Regime Tag ──────────────────────────────────────
let marketRegime;
const spyBreaking = spyStatus.includes('BREAKING_DOWN') || qqqStatus.includes('BREAKING_DOWN');
const spyHealthy  = spyStatus.includes('BULL') || spyStatus.includes('HEALTHY') ||
                    spyStatus.includes('TRENDING');
if      (spyBreaking) marketRegime = 'BEAR';
else if (spyHealthy)  marketRegime = 'BULL';
else                  marketRegime = 'CHOP';

const tradeRegimeTag = `${vixRegime}_VIX_${marketRegime}`;


// ============================================================
// ─────────────────────────────

// v5.2: PRE-PIPELINE KILL SWITCHES
// Kill weak signals at the SM level BEFORE they reach the
// expensive FULL pipeline (Perplexity, VC Agent, etc.)
// Only applies to ENTRY signals routed FULL.
// ============================================================
const isStandAside = execution === 'STAND ASIDE' || direction === 'NEUTRAL';
// v5.3: Block scalp signals outside market hours
if (isScalpTimeframe && !isRegularHours && !isStandAside) {
  const timeReason = isWeekendET ? 'Weekend' : isPreMarket ? 'Pre-market' : isAfterHours ? 'After-hours' : 'Off-hours';
  dedupAction = 'DISCARD';
  dedupReason = timeReason + ' scalp signal blocked: ' + dedupKey + ' at ' + nowHourET + ':' + String(nowMinET).padStart(2, '0') + ' ET';

  state.auditLog.push({
    ts: new Date(now).toISOString(), ticker, timeframe,
    execution, signal, action: 'TIME_BLOCK',
    reason: dedupReason
  });
  if (state.auditLog.length > 1000) state.auditLog.splice(0, state.auditLog.length - 750);

  state.signalStates[dedupKey] = {
    execution, signal, timestamp: now,
    price: d.price || '0', qualityGate: 'TIME_BLOCK', maxConfidence: 0
  };

  return [{
    json: {
      _sm_action: 'TIME_BLOCKED',
      _sm_reason: dedupReason,
      _sm_route: 'SKIP',
      _sm_is_heartbeat: isHeartbeat,
      _sm_version: 'v5.6',
      ticker, timeframe, signal: direction || signal
    }
  }];
}

if (routeAction === 'FULL' && !isStandAside) {
  const killReasons = [];

  // KILL SWITCH 1: Backtest minimum — need at least 10 trades for any statistical relevance
  // v5.16: Skip for scanner signals (BROAD_SCANNER/SENTIMENT_AGENT) — no backtest data available
  const isScannerAlert = (alertType === 'BROAD_SCANNER' || alertType === 'SENTIMENT_AGENT');
  const totalTrades = parseInt(d.strat_total_trades) || 0;
  const profitFactor = parseFloat(d.strat_profit_factor) || 0;
  if (!isScannerAlert && totalTrades < 10) {
    killReasons.push('Backtest insufficient: ' + totalTrades + ' trades (min 10)');
  }
  // PF < 1.0 means negative expectancy — no business sending this to subscribers
  if (!isScannerAlert && totalTrades >= 10 && profitFactor < 1.0) {
    killReasons.push('Negative expectancy: PF=' + profitFactor.toFixed(2) + ' (need >= 1.0)');
  }

  // KILL SWITCH 2: VIX regime — no new entries when VIX > 30 (extreme fear)
  if (vix > 30) {
    killReasons.push('VIX extreme: ' + vix.toFixed(1) + ' > 30 (halt new entries)');
  }

  // KILL SWITCH 3: ADX too low for directional signals — chop kills profits
  // v5.15.1: ADX = N/A means scanner signal — unknown, skip ADX gate
  const _adxRaw = String(d.adx || '').trim();
  const adxLevel = (_adxRaw === 'N/A' || _adxRaw === '' || _adxRaw === '0') ? -1 : (parseFloat(_adxRaw) || -1);
  const adxKnown = adxLevel >= 0; // Only apply ADX gates when we have real data
  if (adxKnown && adxLevel < 15 && (isLong || isShort)) {
    killReasons.push('ADX too low for directional: ' + adxLevel.toFixed(1) + ' < 15 (chop regime)');
  }

  // KILL SWITCH 4: SPY/QQQ both breaking down — no LONG entries
  const _spyBreaking = (d.spy_status || '').includes('BREAKING') || (d.qqq_status || '').includes('BREAKING');
  if (isLong && _spyBreaking) {
    killReasons.push('SPY/QQQ BREAKING DOWN — no longs allowed');
  }

  // KILL SWITCH 5: Daily drawdown halt active
  const _ddHalt = String(d.daily_dd_halt).toLowerCase() === 'true';
  if (_ddHalt) {
    killReasons.push('Daily DD halt active — no new entries');
  }


  // KILL SWITCH 6: REGIME-STRATEGY COMPATIBILITY (v5.4)
  // Block signals inappropriate for current market regime
  // This is the "regime-first architecture" — highest impact filter
  const _regimeTag = vixRegime + '_' + marketRegime;

  // NO mean-reversion LONGS in HIGH_VIX_BEAR
  if (isLong && vix > 25 && marketRegime === 'BEAR') {
    killReasons.push('Regime block: LONG in HIGH_VIX_BEAR (' + _regimeTag + ') — no MR longs in fear');
  }

  // NO counter-trend trades in STRONG_TREND regime
  // adxLevel already declared in kill switch 3
  const dailyTrend = (d.daily_trend || '').toUpperCase();
  if (adxKnown && adxLevel > 35) {
    // Strong trend — only trade WITH the trend
    if (isLong && dailyTrend === 'BEAR') {
      killReasons.push('Regime block: LONG against BEAR daily trend with ADX ' + adxLevel.toFixed(0) + ' (strong trend — trade WITH it)');
    }
    if (isShort && dailyTrend === 'BULL') {
      killReasons.push('Regime block: SHORT against BULL daily trend with ADX ' + adxLevel.toFixed(0) + ' (strong trend — trade WITH it)');
    }
  }

  // NO directional trades in extreme chop (ADX < 12)
  if (adxKnown && adxLevel < 12 && (isLong || isShort)) {
    killReasons.push('Regime block: Directional trade with ADX ' + adxLevel.toFixed(0) + ' < 12 (extreme chop — no edge)');
  }


  // KILL SWITCH 7: ATR VOLATILITY GATE (v5.4)
  // If ATR as % of price is extreme, the stock is too volatile for normal sizing
  const _atrKS = parseFloat(d.atr) || 0;
  const _priceKS = parseFloat(d.price) || 1;
  const atrPct = (_atrKS / _priceKS) * 100;

  if (atrPct > 8) {
    killReasons.push('Extreme volatility: ATR ' + atrPct.toFixed(1) + '% of price (> 8% — untradeable)');
  }

  // If ANY kill switch triggered, downgrade to FAST_ONLY
  if (killReasons.length > 0) {
    routeAction = 'FAST_ONLY';
    dedupReason += ' | DOWNGRADED by kill switches: ' + killReasons.join('; ');

    // Log the kill
    state.auditLog.push({
      ts: new Date(now).toISOString(), ticker, timeframe,
      execution, signal, action: 'KILL_SWITCH',
      reason: killReasons.join('; '),
      kill_count: killReasons.length
    });
    if (state.auditLog.length > 1000) state.auditLog.splice(0, state.auditLog.length - 750);
  }
}

// ── 4. Portfolio Heat Calculations ────────────────────────────
// Manage activePositions: add on LONG/SHORT, remove on STAND ASIDE
const isActiveSignal   = isLong || isShort;
// isStandAside already defined in v5.2 kill switches section above

if (isStandAside && ticker) {
  // Position closed — remove from active positions
  delete state.activePositions[ticker];
} else if (isActiveSignal && ticker) {
  // Position opened or updated — upsert into active positions
  state.activePositions[ticker] = {
    ticker,
    direction,
    timeframe,
    entryTime:      new Date(now).toISOString(),
    price:          d.price || '0',
    vix_size_mult:  vixSizeMult,
    eff_position_size: effPositionSz
  };
}

// Snapshot counts AFTER update for contradiction evaluation
const activePosCount  = Object.keys(state.activePositions).length;
const activePosList   = Object.values(state.activePositions);

// Same-direction count (excluding the current ticker to avoid double-counting)
const sameDirCount = activePosList.filter(function(p) {
  return p.ticker !== ticker && p.direction === direction;
}).length;

// Portfolio heat: sum of all eff_position_size
let portfolioHeatPct = 0;
activePosList.forEach(function(p) {
  portfolioHeatPct += (parseFloat(p.eff_position_size) || 0);
});
portfolioHeatPct = parseFloat(portfolioHeatPct.toFixed(2));

// ── 5. Contradiction Detection — HARD vs SOFT ─────────────────
const hardContradictions = [];
const softContradictions = [];

// HARD: Cross-asset hostile / crisis
if (crossAsset === 'HOSTILE' || crossAsset === 'CRISIS') {
  hardContradictions.push(`Cross-asset ${crossAsset}`);
}
// HARD: SPY or QQQ breaking down on a LONG
if (isLong && spyBreaking) {
  hardContradictions.push(`SPY/QQQ BREAKING_DOWN vs LONG`);
}
// HARD: VIX > 30 on a LONG
if (isLong && vix > 30) {
  hardContradictions.push(`VIX ${vix.toFixed(1)} > 30 vs LONG`);
}
// HARD: Gamma squeeze down vs LONG
if (isLong && (gexSign === 'NEGATIVE' && optRegime.includes('SQUEEZE_DOWN'))) {
  hardContradictions.push(`GAMMA_SQUEEZE_DOWN vs LONG`);
}
// HARD: Regime not tradeable
if (d.tradeable_environment === false || d.tradeable_environment === 'false') {
  hardContradictions.push(`Environment not tradeable`);
}
// HARD: Daily drawdown halt (from Pine Script)
if (dailyDdHalt) {
  hardContradictions.push(`Daily drawdown halt active (DD: ${dailyDdPct.toFixed(2)}%)`);
}
// HARD: Portfolio heat limit (concurrent positions)
if (isActiveSignal && activePosCount >= MAX_CONCURRENT) {
  hardContradictions.push(`Portfolio heat limit: ${activePosCount}/${MAX_CONCURRENT} positions active`);
}

// SOFT: Cross-asset RISK_OFF vs LONG
if (isLong && crossAsset === 'RISK_OFF') {
  softContradictions.push(`Cross-asset RISK_OFF vs LONG`);
}
// SOFT: Elevated VIX 25-30
if (vix >= 25 && vix <= 30) {
  softContradictions.push(`Elevated VIX ${vix.toFixed(1)} (25-30)`);
}
// SOFT: Dark pool distribution
const dpDistribution = dpSignal.includes('DISTRIBUTION') ||
                       dpSignal.includes('SELLING') ||
                       dpSignal.includes('BEARISH');
if (isLong && dpDistribution) {
  softContradictions.push(`Dark pool DISTRIBUTION vs LONG`);
}
// SOFT: RSI overbought/oversold
if ((isLong && rsi > 70) || (isShort && rsi < 30)) {
  softContradictions.push(`RSI ${rsi.toFixed(1)} extreme vs ${direction}`);
}
// SOFT: Negative backtest
if (stratNetPct < 0) {
  softContradictions.push(`Negative backtest (${stratNetPct.toFixed(1)}%)`);
}
// SOFT: VIX > 30 on SHORT
if (isShort && vix > 30) {
  softContradictions.push(`VIX ${vix.toFixed(1)} > 30 (short ${String.fromCharCode(8212)} macro tailwind)`);
}
// HARD: Same-direction limit (v5.17: upgraded from soft to hard)
if (isActiveSignal && sameDirCount >= MAX_SAME_DIRECTION) {
  hardContradictions.push(`Same-direction limit: ${sameDirCount}/${MAX_SAME_DIRECTION} already ${direction}`);
}
// HARD: Portfolio heat limit (v5.17: upgraded from soft to hard)
// With real money, NEVER allow new positions when heat exceeds threshold.
// This is the last line of defense before capital allocation.
if (isActiveSignal && portfolioHeatPct > MAX_HEAT_PCT) {
  hardContradictions.push(`Portfolio heat ${portfolioHeatPct}% > ${MAX_HEAT_PCT}% cap`);
}

// ── 6. Correlation Filter ─────────────────────────────────────
let correlationWarning = 'none';
if (isActiveSignal && ticker) {
  const tickerGroup = getCorrelationGroup(ticker);
  if (tickerGroup) {
    const groupMembers = CORRELATION_GROUPS[tickerGroup];
    // Find any active position in the same group + same direction (excluding self)
    const correlatedMatch = activePosList.find(function(p) {
      return p.ticker !== ticker &&
             groupMembers.includes(p.ticker) &&
             p.direction === direction;
    });
    if (correlatedMatch) {
      correlationWarning = `Correlated position: ${correlatedMatch.ticker} already ${direction} in ${tickerGroup} group`;
      softContradictions.push(correlationWarning);
    }
  }
}

// ── System-wide DD halt note (add to smReason later) ──────────
// Will be appended in smReason build below

const totalHard        = hardContradictions.length;
const allContradictions = [...hardContradictions, ...softContradictions];

// ── 7. KILL Gate ──────────────────────────────────────────────
// v5.17: Portfolio-level blocks (heat, position count, same-direction)
// are INSTANT KILL — single hard contradiction is enough.
// Other hard contradictions still need 2+ to kill.
const KILL_THRESHOLD = 2;
const _hasPortfolioBlock = hardContradictions.some(c =>
  c.includes('heat') || c.includes('Portfolio') || c.includes('Same-direction')
);
const killed = _hasPortfolioBlock || (totalHard >= KILL_THRESHOLD);

if (killed) {
  state.signalStates[dedupKey] = {
    execution, signal, alertType, timestamp: now,
    price: d.price || '0', qualityGate: 'KILL', maxConfidence: 0
  };

  const entry = {
    ts: new Date(now).toISOString(), ticker, timeframe, direction,
    hard: hardContradictions, soft: softContradictions
  };
  state.contradictions.push(entry);
  if (state.contradictions.length > 1000) state.contradictions.splice(0, state.contradictions.length - 750);

  state.auditLog.push({ ts: entry.ts, ticker, timeframe, action: 'KILLED',
    reason: hardContradictions.join(' | ') });
  if (state.auditLog.length > 1000) state.auditLog.splice(0, state.auditLog.length - 750);

  return [{
    json: {
      ...d,
      _sm_action:                'KILLED',
      _sm_reason:                `KILL gate triggered ${String.fromCharCode(8212)} ${totalHard} HARD contradictions`,
      _sm_route:                 'SKIP',
      _sm_is_heartbeat:          isHeartbeat,
      _sm_heartbeat_promoted:    false,
      _sm_raw_score:             rawScore,
      _sm_contradiction_details: hardContradictions.join(' | '),
      _sm_soft_contradictions:   softContradictions.join(' | ') || 'none',
      _sm_vix_regime:            vixRegime,
      _sm_market_regime:         marketRegime,
      _sm_trade_regime_tag:      tradeRegimeTag,
      _sm_prev_execution:        prev ? prev.execution : 'NONE',
      _sm_prev_signal:           prev ? prev.signal : 'NONE',
      _sm_seconds_since_last:    prev ? Math.round((now - prev.timestamp) / 1000) : 0,
      // v5 portfolio fields
      _sm_active_positions:      activePosCount,
    _sm_active_tickers:        Object.keys(state.activePositions).join(','),
    test_mode:                 _isTestSignal,
      _sm_same_direction_count:  sameDirCount,
      _sm_portfolio_heat_pct:    portfolioHeatPct,
      _sm_daily_dd_halt_tickers: ddHaltTickersList.join(',') || 'none',
      _sm_correlation_warning:   correlationWarning,
      _sm_daily_pnl_summary:     `Date: ${today} | DD Halt Tickers: ${ddHaltTickersList.length} | SystemWideHalt: ${systemWideDDHalt}`,
      _sm_version:               'v5.6',
      ticker, timeframe, signal: direction
    }
  }];
}

// ── v5.17: Telegram alert when portfolio heat or same-direction blocks ─────
// Fires only once per trading day per block type to avoid spam.
if (killed) {
  const _heatBlocked = hardContradictions.some(c => c.includes('heat') || c.includes('Same-direction'));
  if (_heatBlocked) {
    if (!state._heatAlertSentToday) state._heatAlertSentToday = {};
    const _heatAlertKey = today + '_' + ticker;
    if (!state._heatAlertSentToday[_heatAlertKey]) {
      state._heatAlertSentToday[_heatAlertKey] = Date.now();
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: '6648680513',
            text: `\u26a0\ufe0f <b>SIGNAL BLOCKED — Portfolio Heat</b>\n` +
                  `Ticker: ${ticker} (${direction})\n` +
                  `Heat: ${portfolioHeatPct}% / ${MAX_HEAT_PCT}% cap\n` +
                  `Active: ${activePosCount} positions, ${sameDirCount} same-direction\n` +
                  `Reason: ${hardContradictions.filter(c => c.includes('heat') || c.includes('Same-direction')).join(', ')}\n` +
                  `<i>New signals blocked until heat drops below ${MAX_HEAT_PCT}%</i>`,
            parse_mode: 'HTML'
          }),
          json: true
        });
      } catch (_tgErr) { /* silent */ }
    }
  }
  // Clean stale alert keys (keep only today's)
  for (const k of Object.keys(state._heatAlertSentToday || {})) {
    if (!k.startsWith(today)) delete state._heatAlertSentToday[k];
  }
}

// ── 8. Confidence Caps ────────────────────────────────────────
let rawConfidence = Math.min(confidence, 9);
let capReason     = '';

// GEX contradicts technicals
const gexContradictsLong  = isLong  && gexSign === 'NEGATIVE';
const gexContradictsShort = isShort && gexSign === 'POSITIVE';
if (gexContradictsLong || gexContradictsShort) {
  if (rawConfidence > 6) { rawConfidence = 6; capReason = `Cap 6 (GEX contradicts ${direction})`; }
}

// Cross-asset HOSTILE → 3
if (crossAsset === 'HOSTILE') {
  if (rawConfidence > 3) { rawConfidence = 3; capReason = 'Cap 3 (Cross-asset HOSTILE)'; }
}
// Cross-asset RISK_OFF + LONG → 7
if (isLong && crossAsset === 'RISK_OFF') {
  if (rawConfidence > 7) { rawConfidence = 7; capReason = 'Cap 7 (Cross-asset RISK_OFF vs LONG)'; }
}
// VIX > 30 + LONG → 4
if (isLong && vix > 30) {
  if (rawConfidence > 4) { rawConfidence = 4; capReason = `Cap 4 (VIX ${vix.toFixed(1)} >30 vs LONG)`; }
}
// VIX 25-30 + LONG → 7
if (isLong && vix >= 25 && vix <= 30) {
  if (rawConfidence > 7) { rawConfidence = 7; capReason = `Cap 7 (VIX ${vix.toFixed(1)} 25-30 vs LONG)`; }
}
// SPY/QQQ BREAKING_DOWN + LONG → 3
if (isLong && spyBreaking) {
  if (rawConfidence > 3) { rawConfidence = 3; capReason = 'Cap 3 (SPY/QQQ BREAKING_DOWN vs LONG)'; }
}
// Dark pool DISTRIBUTION + LONG → 6
if (isLong && dpDistribution) {
  if (rawConfidence > 6) { rawConfidence = 6; capReason = 'Cap 6 (Dark pool DISTRIBUTION vs LONG)'; }
}

// 9/10 gate — ALL criteria must pass
if (rawConfidence >= 9) {
  const rsiOk       = rsi >= 30 && rsi <= 70;
  const macdAligned = isLong ? macdHist > 0 : macdHist < 0;
  const adxOk       = adx > 20;
  const smaOk       = isLong ? priceVsSma50 === 'ABOVE' : priceVsSma50 === 'BELOW';
  const vixOk       = vix < 25;
  const caOk        = crossAsset !== 'RISK_OFF' && crossAsset !== 'HOSTILE';
  const optOk       = optRegime.includes('BULLISH') && isLong ||
                      optRegime.includes('BEARISH') && isShort ||
                      optRegime.includes('CONTRARIAN_LONG') && isLong ||
                      optRegime.includes('CONTRARIAN_SHORT') && isShort;
  const dpOk        = !dpDistribution;

  const nineGatePassed = rsiOk && macdAligned && adxOk && smaOk && vixOk && caOk && optOk && dpOk;
  if (!nineGatePassed) {
    rawConfidence = 8;
    const fails = [];
    if (!rsiOk)       fails.push(`RSI ${rsi.toFixed(0)} out of 30-70`);
    if (!macdAligned) fails.push(`MACD histogram not aligned`);
    if (!adxOk)       fails.push(`ADX ${adx.toFixed(0)} ${String.fromCharCode(8804)} 20`);
    if (!smaOk)       fails.push(`Price not ${isLong ? 'above' : 'below'} SMA50`);
    if (!vixOk)       fails.push(`VIX ${vix.toFixed(1)} ${String.fromCharCode(8805)} 25`);
    if (!caOk)        fails.push(`Cross-asset not neutral`);
    if (!optOk)       fails.push(`Options not aligned`);
    if (!dpOk)        fails.push(`Dark pool distribution`);
    capReason = `Cap 8 (9/10 gate failed: ${fails.join(', ')})`;
  }
}

const finalConfidence = Math.round(rawConfidence);

// ── 9. Factor Attribution ─────────────────────────────────────
const boosts     = [];
const reductions = [];
let netAdj = 0;

if ((isLong  && (optRegime.includes('BULLISH') || optRegime.includes('CONTRARIAN_LONG'))) ||
    (isShort && (optRegime.includes('BEARISH') || optRegime.includes('CONTRARIAN_SHORT')))) {
  boosts.push(`+1 Options aligned (${optRegime})`); netAdj += 1;
}
if (adx > 25) {
  boosts.push(`+1 Strong trend (ADX ${adx.toFixed(0)})`); netAdj += 1;
}
if ((isLong && mtfBullOk) || (isShort && mtfBearOk)) {
  boosts.push(`+1 MTF confluence confirmed`); netAdj += 1;
}
if (relVol > 1.2) {
  boosts.push(`+1 Volume above avg (${relVol.toFixed(2)}x)`); netAdj += 1;
}

if (isLong && crossAsset === 'RISK_OFF') {
  reductions.push(`-1 Cross-asset RISK_OFF`); netAdj -= 1;
}
if (isLong && dpDistribution) {
  reductions.push(`-1 Dark pool DISTRIBUTION`); netAdj -= 1;
}
if (vix > 25) {
  reductions.push(`-1 VIX elevated (${vix.toFixed(1)})`); netAdj -= 1;
}
if ((isLong && rsi > 70) || (isShort && rsi < 30)) {
  reductions.push(`-1 RSI extreme (${rsi.toFixed(0)})`); netAdj -= 1;
}
if (stratNetPct < 0) {
  reductions.push(`-2 Negative backtest (${stratNetPct.toFixed(1)}%)`); netAdj -= 2;
}
// v5: VIX-reduced sizing factor
if (vixSizeMult < 1.0) {
  reductions.push(`-1 VIX-reduced sizing (${vixSizeMult}x)`); netAdj -= 1;
}

const capNote = capReason ? ` | Cap: ${capReason}` : ` | Cap: none`;
const factorAttribution = [
  ...boosts,
  ...reductions,
  `Net adjustment: ${netAdj >= 0 ? '+' : ''}${netAdj}${capNote}`
].join(' | ');

// ── 10. Quality Gate ──────────────────────────────────────────
const qualityGate = finalConfidence >= 6 && totalHard === 0 ? 'PASS' : 'REVIEW';

// ── 11. Build reason string ───────────────────────────────────
let smReason = `${dedupReason} | ${direction} on ${ticker} ${timeframe} | Confidence ${finalConfidence}/9`;
if (heartbeatPromoted) {
  smReason += ` | HEARTBEAT PROMOTED (score ${rawScore} > ${HEARTBEAT_SCORE_THRESHOLD})`;
}
if (allContradictions.length > 0) {
  smReason += ` | Contradictions: ${allContradictions.join('; ')}`;
}
if (capReason) smReason += ` | ${capReason}`;
if (systemWideDDHalt) smReason += ` | SYSTEM-WIDE DD HALT (${ddHaltTickersList.join(',')})`;

// ── 12. Daily P&L summary ─────────────────────────────────────
const dailyPnlSummary = `Date: ${today} | PnL: ${state.dailyPnL.totalPnL.toFixed(2)} | Trades: ${state.dailyPnL.trades.length} | DD Halt Tickers: ${ddHaltTickersList.length} | SystemWideHalt: ${systemWideDDHalt}`;

// ── 13. Update state for future dedup ─────────────────────────
state.signalStates[dedupKey] = {
  execution, signal, alertType, timestamp: now,
  price: d.price || '0', qualityGate, maxConfidence: finalConfidence
};

// ── 14. Audit Log ─────────────────────────────────────────────
state.auditLog.push({
  ts:          new Date(now).toISOString(),
  ticker,
  timeframe,
  direction,
  confidence:  finalConfidence,
  rawScore,
  action:      qualityGate === 'KILL' ? 'KILLED' : 'FORWARD',
  route:       routeAction,
  isHeartbeat,
  heartbeatPromoted,
  hardCount:   totalHard,
  softCount:   softContradictions.length,
  regime:      tradeRegimeTag,
  reason:      smReason,
  activePositions: activePosCount,
  portfolioHeat:   portfolioHeatPct
});
if (state.auditLog.length > 1000) state.auditLog.splice(0, state.auditLog.length - 750);

// Contradiction log
state.contradictions.push({
  ts: new Date(now).toISOString(),
  ticker, direction,
  contradictionCount: allContradictions.length,
  maxConfidence:      finalConfidence,
  gate:               qualityGate,
  details:            allContradictions.join('; ') || 'none',
  vix, regime: crossAsset, optRegime,
  portfolioHeat: portfolioHeatPct,
  ddHaltTickers: ddHaltTickersList.join(',') || 'none'
});
if (state.contradictions.length > 1000) state.contradictions.splice(0, state.contradictions.length - 750);

// ── 15. Return enriched item ──────────────────────────────────
return [{
  json: {
    // ── pass-through all original fields ──────────────────
    ...d,

    // ── state machine outputs ──────────────────────────────
    _sm_version:               'v5.6',
    _sm_action:                'PASS',
    _sm_route:                 routeAction,
    _sm_is_heartbeat:          isHeartbeat,
    _sm_heartbeat_promoted:    heartbeatPromoted,
    _sm_promotion_reason:      promotionReason || 'none',
    _sm_raw_score:             rawScore,
    _sm_reason:                smReason,
    _sm_max_confidence:        finalConfidence,
    _sm_quality_gate:          qualityGate,

    // dedup fields
    _sm_prev_execution:        prev ? prev.execution : 'NONE',
    _sm_prev_signal:           prev ? prev.signal : 'NONE',
    _sm_seconds_since_last:    prev ? Math.round((now - prev.timestamp) / 1000) : 0,

    // contradiction output
    _sm_contradiction_count:      allContradictions.length,
    _sm_hard_contradiction_count: totalHard,
    _sm_contradiction_details:    allContradictions.join(' | ') || 'none',
    _sm_hard_contradictions:      hardContradictions.join(' | ') || 'none',
    _sm_soft_contradictions:      softContradictions.join(' | ') || 'none',

    // v3+ fields
    _sm_factor_attribution:    factorAttribution,
    _sm_vix_regime:            vixRegime,
    _sm_market_regime:         marketRegime,
    _sm_trade_regime_tag:      tradeRegimeTag,

    // cap traceability
    _sm_confidence_cap_reason: capReason || 'none',
    _sm_raw_confidence:        Math.round(Math.min(confidence, 9)),

    // ── v5 portfolio risk fields ───────────────────────────
    _sm_active_positions:      activePosCount,
    _sm_active_tickers:        Object.keys(state.activePositions).join(','),
    test_mode:                 _isTestSignal,
    _sm_same_direction_count:  sameDirCount,
    _sm_portfolio_heat_pct:    portfolioHeatPct,
    _sm_daily_dd_halt_tickers: ddHaltTickersList.join(',') || 'none',
    _sm_correlation_warning:   correlationWarning,
    _sm_daily_pnl_summary:     dailyPnlSummary
  }
}];

// ============================================================
// OPTIONS FLOW ENGINE v1 — Institutional-Grade GEX + Flow
// Phase 2.2 of Quantum Engineering Trading Pipeline
//
// PHILOSOPHY (Citadel/RenTech-inspired):
// Dealers must delta-hedge. +GEX = mean-reversion. -GEX = breakout.
// This node fetches the options chain AND computes 10 metrics.
//
// COMPUTES: GEX, GEX Flip, P/C Ratio, Max Pain, Dealer Walls,
//   Unusual Activity, 0DTE Skew, IV Skew, Gamma Wall, Options Regime
//
// INSERT: After Backtest Engine, before Perplexity AI Analysis
// ============================================================

// Signal data from Backtest Engine (upstream), options from HTTP input
const beItem = $('Backtest Engine').first();
if (!beItem || !beItem.json) {
  return [{ json: { opt_error: 'No input from Backtest Engine' } }];
}
const prev = beItem.json;
const ticker = prev.ticker || 'UNKNOWN';
const price = parseFloat(prev.price) || 0;

try {
const now = Date.now();

// API key is in the 'Fetch Options Chain' HTTP Request node

// ============================================================
// CONFIG
// ============================================================
// Strike range configured in HTTP node
// Max contracts configured in HTTP node
const UNUSUAL_VOL_OI_RATIO = 3.0;
const UNUSUAL_MIN_VOLUME = 500;
const UNUSUAL_MIN_PREMIUM = 50000;
const DEALER_WALL_OI_MULTIPLIER = 3.0;
const PC_EXTREME_HIGH = 1.2;
const PC_EXTREME_LOW = 0.6;

// ============================================================
// SKIP if no valid price or API key not set
// ============================================================
if (price <= 0) {
  return [{
    json: {
      ...prev,
      options_regime: 'NO_PRICE',
      options_regime_confidence: 'NONE',
      options_summary: 'No valid price for options analysis',
      opt_regime: 'UNAVAILABLE',
      opt_regime_confidence: 'NONE',
      opt_regime_detail: ''
    }
  }];
}

// Options chain data comes from "Fetch Options Chain" HTTP Request node
const todayObj = new Date();
const todayStr = todayObj.toISOString().split('T')[0];

// Get options chain from HTTP Request node (direct input)
let allContracts = [];
try {
  const optData = $('Fetch Options Chain').first().json;
  allContracts = optData.results || [];
} catch (err) {
  allContracts = [];
}

if (allContracts.length === 0) {
  return [{
    json: {
      ...prev,
      options_regime: 'NO_DATA',
      options_regime_confidence: 'NONE',
      options_summary: 'No options contracts returned for ' + ticker,
      opt_regime: 'NO_DATA',
      opt_regime_confidence: 'NONE',
      opt_regime_detail: ''
    }
  }];
}

// ============================================================
// PARSE CONTRACTS
// ============================================================
const calls = [];
const puts = [];
const expirations = new Set();
let spotPrice = price;

for (const c of allContracts) {
  const d = c.details || {};
  const g = c.greeks || {};
  const day = c.day || {};

  if (c.underlying_asset && c.underlying_asset.price > 0) {
    spotPrice = c.underlying_asset.price;
  }

  const ct = {
    strike: d.strike_price || 0,
    expiration: d.expiration_date || '',
    type: d.contract_type || '',
    oi: c.open_interest || 0,
    volume: day.volume || 0,
    delta: g.delta || 0,
    gamma: g.gamma || 0,
    iv: c.implied_volatility || 0,
    dayClose: day.close || 0
  };

  expirations.add(ct.expiration);
  if (ct.type === 'call') calls.push(ct);
  else if (ct.type === 'put') puts.push(ct);
}

const sortedExps = Array.from(expirations).sort();
const nearestExp = sortedExps[0] || todayStr;
const is0DTE = nearestExp === todayStr;

// ============================================================
// 1. NET GEX — Dealer gamma exposure
// ============================================================
let callGEX = 0;
let putGEX = 0;
const gexByStrike = {};

for (const c of calls) {
  const gex = c.gamma * c.oi * 100 * spotPrice;
  callGEX += gex;
  if (!gexByStrike[c.strike]) gexByStrike[c.strike] = 0;
  gexByStrike[c.strike] += gex;
}
for (const p of puts) {
  const gex = p.gamma * p.oi * 100 * spotPrice;
  putGEX += gex;
  if (!gexByStrike[p.strike]) gexByStrike[p.strike] = 0;
  gexByStrike[p.strike] -= gex;
}

const netGEX = callGEX - putGEX;

function fmtDollar(v) {
  const a = Math.abs(v);
  const s = v >= 0 ? '+' : '-';
  if (a >= 1e9) return s + '$' + (a / 1e9).toFixed(2) + 'B';
  if (a >= 1e6) return s + '$' + (a / 1e6).toFixed(1) + 'M';
  if (a >= 1e3) return s + '$' + (a / 1e3).toFixed(0) + 'K';
  return s + '$' + a.toFixed(0);
}

// ============================================================
// 2. GEX FLIP LEVEL
// ============================================================
let gexFlip = 0;
const strikes = Object.keys(gexByStrike).map(Number).sort((a, b) => a - b);

for (let i = 0; i < strikes.length - 1; i++) {
  const g1 = gexByStrike[strikes[i]];
  const g2 = gexByStrike[strikes[i + 1]];
  if ((g1 > 0 && g2 < 0) || (g1 < 0 && g2 > 0)) {
    gexFlip = strikes[i] + (strikes[i + 1] - strikes[i]) * Math.abs(g1) / (Math.abs(g1) + Math.abs(g2));
    break;
  }
}

// ============================================================
// 3. PUT/CALL RATIO
// ============================================================
let tCallOI = 0, tPutOI = 0, tCallVol = 0, tPutVol = 0;
for (const c of calls) { tCallOI += c.oi; tCallVol += c.volume; }
for (const p of puts) { tPutOI += p.oi; tPutVol += p.volume; }

const pcOI = tCallOI > 0 ? tPutOI / tCallOI : 0;
const pcVol = tCallVol > 0 ? tPutVol / tCallVol : 0;

let pcSent = 'NEUTRAL';
if (pcOI > PC_EXTREME_HIGH) pcSent = 'EXTREME_FEAR';
else if (pcOI > 1.0) pcSent = 'BEARISH';
else if (pcOI < PC_EXTREME_LOW) pcSent = 'EXTREME_GREED';
else if (pcOI < 0.8) pcSent = 'BULLISH';

// ============================================================
// 4. MAX PAIN
// ============================================================
let maxPainStrike = 0;
let minPain = Infinity;

for (const sk of strikes) {
  let tp = 0;
  for (const c of calls) { if (sk > c.strike) tp += (sk - c.strike) * c.oi * 100; }
  for (const p of puts) { if (sk < p.strike) tp += (p.strike - sk) * p.oi * 100; }
  if (tp < minPain) { minPain = tp; maxPainStrike = sk; }
}

const mpDist = spotPrice > 0 ? ((maxPainStrike - spotPrice) / spotPrice * 100).toFixed(2) : '0';

// ============================================================
// 5. DEALER WALLS
// ============================================================
const allOIs = [...calls, ...puts].map(c => c.oi).filter(v => v > 0);
const avgOI = allOIs.length > 0 ? allOIs.reduce((a, b) => a + b, 0) / allOIs.length : 0;
const wallThr = avgOI * DEALER_WALL_OI_MULTIPLIER;

const cWalls = calls.filter(c => c.oi > wallThr && c.oi > 500).sort((a, b) => b.oi - a.oi).slice(0, 3);
const pWalls = puts.filter(p => p.oi > wallThr && p.oi > 500).sort((a, b) => b.oi - a.oi).slice(0, 3);

// ============================================================
// 6. UNUSUAL ACTIVITY
// ============================================================
const unusual = [];
for (const c of [...calls, ...puts]) {
  if (c.volume < UNUSUAL_MIN_VOLUME) continue;
  const ratio = c.oi > 0 ? c.volume / c.oi : c.volume;
  const prem = c.volume * c.dayClose * 100;
  if (ratio >= UNUSUAL_VOL_OI_RATIO && prem >= UNUSUAL_MIN_PREMIUM) {
    unusual.push({
      strike: c.strike, type: c.type.toUpperCase(), volume: c.volume,
      oi: c.oi, ratio: ratio.toFixed(1), prem: Math.round(prem), exp: c.expiration
    });
  }
}
unusual.sort((a, b) => b.prem - a.prem);
const topUnu = unusual.slice(0, 5);

// ============================================================
// 7. 0DTE SKEW
// ============================================================
let odteC = 0, odteP = 0;
if (is0DTE) {
  for (const c of calls) { if (c.expiration === todayStr) odteC += c.volume; }
  for (const p of puts) { if (p.expiration === todayStr) odteP += p.volume; }
}
const odteT = odteC + odteP;

// ============================================================
// 8. IV SKEW
// ============================================================
const atmR = spotPrice * 0.02;
const atmCalls = calls.filter(c => Math.abs(c.strike - spotPrice) <= atmR && c.iv > 0 && c.expiration === nearestExp);
const atmPuts = puts.filter(p => Math.abs(p.strike - spotPrice) <= atmR && p.iv > 0 && p.expiration === nearestExp);

const avgCIV = atmCalls.length > 0 ? atmCalls.reduce((s, c) => s + c.iv, 0) / atmCalls.length : 0;
const avgPIV = atmPuts.length > 0 ? atmPuts.reduce((s, p) => s + p.iv, 0) / atmPuts.length : 0;
const ivSkew = avgPIV - avgCIV;

let ivSig = 'NEUTRAL';
if (ivSkew > 0.05) ivSig = 'FEAR_PREMIUM';
else if (ivSkew > 0.02) ivSig = 'MILD_FEAR';
else if (ivSkew < -0.02) ivSig = 'CALL_PREMIUM';

// ============================================================
// 9. GAMMA WALL
// ============================================================
let gWallStrike = 0, gWallVal = 0;
for (const c of [...calls, ...puts]) {
  const gxoi = Math.abs(c.gamma) * c.oi;
  if (gxoi > gWallVal) { gWallVal = gxoi; gWallStrike = c.strike; }
}

// ============================================================
// 10. OPTIONS REGIME — Institutional decision tree
// ============================================================
let optRegime = 'NEUTRAL';
let regConf = 'LOW';
let regDetail = '';

if (netGEX > 0) {
  if (pcSent === 'EXTREME_FEAR') {
    optRegime = 'CONTRARIAN_LONG'; regConf = 'HIGH';
    regDetail = '+GEX + extreme fear = dealers buy dips aggressively. Mean-reversion long.';
  } else if (pcSent === 'EXTREME_GREED') {
    optRegime = 'CONTRARIAN_SHORT'; regConf = 'MODERATE';
    regDetail = '+GEX + extreme greed = dealers cap upside. Expect fade.';
  } else {
    optRegime = 'MEAN_REVERSION'; regConf = 'MODERATE';
    regDetail = '+GEX: dealers sell rallies, buy dips. Range-bound. Fade extremes.';
  }
} else {
  if (pcSent === 'EXTREME_FEAR' || pcSent === 'BEARISH') {
    optRegime = 'GAMMA_SQUEEZE_DOWN'; regConf = 'HIGH';
    regDetail = '-GEX + bearish flow = downside amplification. Danger zone for longs.';
  } else if (pcSent === 'EXTREME_GREED' || pcSent === 'BULLISH') {
    optRegime = 'GAMMA_SQUEEZE_UP'; regConf = 'HIGH';
    regDetail = '-GEX + bullish flow = upside amplification. Momentum favored.';
  } else {
    optRegime = 'BREAKOUT'; regConf = 'MODERATE';
    regDetail = '-GEX: dealers amplify direction. Breakout imminent.';
  }
}

// IV skew overlay
if (ivSig === 'FEAR_PREMIUM' && optRegime.includes('UP')) {
  regDetail += ' CAUTION: IV skew shows put premium despite bullish flow.';
}
if (ivSig === 'CALL_PREMIUM' && optRegime.includes('DOWN')) {
  regDetail += ' CAUTION: IV skew shows call premium despite bearish flow.';
}

// Unusual activity overlay
const unuC = topUnu.filter(u => u.type === 'CALL').length;
const unuP = topUnu.filter(u => u.type === 'PUT').length;
const unuBias = unuC > unuP ? 'CALL_HEAVY' : unuP > unuC ? 'PUT_HEAVY' : 'BALANCED';

if (topUnu.length >= 3) {
  if (unuBias === 'CALL_HEAVY' && (optRegime.includes('UP') || optRegime === 'CONTRARIAN_LONG')) {
    regConf = 'VERY_HIGH';
    regDetail += ' Institutional sweeps confirm bullish conviction.';
  } else if (unuBias === 'PUT_HEAVY' && (optRegime.includes('DOWN') || optRegime === 'CONTRARIAN_SHORT')) {
    regConf = 'VERY_HIGH';
    regDetail += ' Institutional sweeps confirm bearish conviction.';
  }
}

// ============================================================
// BUILD SUMMARY TEXT for Telegram
// ============================================================
const NL = String.fromCharCode(10);
let sum = '';
sum += 'GEX: ' + fmtDollar(netGEX) + ' (' + (netGEX >= 0 ? 'Positive: dealers stabilize' : 'Negative: dealers amplify') + ')';
sum += NL + 'GEX Flip: $' + (gexFlip > 0 ? gexFlip.toFixed(2) : 'N/A') + ' | Gamma Wall: $' + gWallStrike;
sum += NL + 'P/C Ratio: ' + pcOI.toFixed(2) + ' OI / ' + pcVol.toFixed(2) + ' Vol | ' + pcSent;
sum += NL + 'Max Pain: $' + maxPainStrike + ' (' + mpDist + '% from spot)';
sum += NL + 'IV Skew: ' + (ivSkew * 100).toFixed(1) + '% | ' + ivSig;

if (is0DTE && odteT > 0) {
  const odteCPct = (odteC / odteT * 100).toFixed(0);
  const odtePPct = (odteP / odteT * 100).toFixed(0);
  sum += NL + '0DTE: ' + odteCPct + '% calls / ' + odtePPct + '% puts (' + odteT.toLocaleString() + ' contracts)';
}

if (cWalls.length > 0) sum += NL + 'Call Walls: ' + cWalls.map(w => '$' + w.strike + '(' + w.oi.toLocaleString() + ')').join(', ');
if (pWalls.length > 0) sum += NL + 'Put Walls: ' + pWalls.map(w => '$' + w.strike + '(' + w.oi.toLocaleString() + ')').join(', ');

if (topUnu.length > 0) {
  sum += NL + 'Unusual: ' + topUnu.length + ' sweeps (' + unuBias + ')';
  for (const u of topUnu.slice(0, 3)) {
    sum += NL + '  ' + u.type + ' $' + u.strike + ' exp ' + u.exp + ' | Vol ' + u.volume.toLocaleString() + ' vs OI ' + u.oi.toLocaleString() + ' (' + u.ratio + 'x) | ~$' + (u.prem / 1000).toFixed(0) + 'K';
  }
} else {
  sum += NL + 'Unusual: None detected';
}

sum += NL + 'REGIME: ' + optRegime + ' (' + regConf + ')';
sum += NL + regDetail;

// ============================================================
// OUTPUT
// ============================================================
return [{
  json: {
    ...prev,

    // Flat fields for Perplexity prompt expressions
    opt_net_gex: fmtDollar(netGEX),
    opt_gex_sign: netGEX >= 0 ? 'POSITIVE' : 'NEGATIVE',
    opt_gex_flip: gexFlip > 0 ? '$' + gexFlip.toFixed(2) : 'N/A',
    opt_gamma_wall: '$' + gWallStrike,
    opt_pc_ratio_oi: pcOI.toFixed(2),
    opt_pc_ratio_vol: pcVol.toFixed(2),
    opt_pc_sentiment: pcSent,
    opt_max_pain: '$' + maxPainStrike,
    opt_max_pain_dist: mpDist + '%',
    opt_iv_skew: (ivSkew * 100).toFixed(1) + '%',
    opt_iv_skew_signal: ivSig,
    opt_call_walls: cWalls.map(w => '$' + w.strike + '(' + w.oi.toLocaleString() + ')').join(', ') || 'None',
    opt_put_walls: pWalls.map(w => '$' + w.strike + '(' + w.oi.toLocaleString() + ')').join(', ') || 'None',
    opt_unusual_count: topUnu.length,
    opt_unusual_bias: unuBias,
    opt_unusual_detail: topUnu.slice(0, 3).map(u =>
      u.type + ' $' + u.strike + ' ' + u.exp + ' vol=' + u.volume + ' ~$' + (u.prem / 1000).toFixed(0) + 'K'
    ).join('; ') || 'None',
    opt_0dte: is0DTE && odteT > 0
      ? (odteC / odteT * 100).toFixed(0) + '% calls / ' + (odteP / odteT * 100).toFixed(0) + '% puts'
      : 'N/A',
    opt_regime: optRegime,
    opt_regime_confidence: regConf,
    opt_regime_detail: regDetail,
    opt_contracts: allContracts.length,
    opt_nearest_exp: nearestExp,

    // Full summary for Telegram format node
    options_summary: sum,
    options_regime: optRegime,
    options_regime_confidence: regConf
  }
}];

} catch (engineError) {
  return [{
    json: {
      ...prev,
      opt_regime: 'ERROR',
      opt_regime_confidence: 'NONE',
      options_summary: 'Options engine error: ' + (engineError.message || 'unknown'),
      opt_error: engineError.message || 'Options Flow Engine failed',
    }
  }];
}

// ============================================================
// DARK POOL & INSTITUTIONAL FLOW ENGINE v1
// Phase 2.3 of Quantum Engineering Trading Pipeline
//
// PHILOSOPHY (Citadel/RenTech-inspired):
// Retail volume does not move markets. Institutional positioning
// reveals where the real money is committed. This engine combines
// multiple free data sources to approximate dark pool intelligence:
//
// DATA SOURCES:
//   A) FINRA Short Volume (daily) — short ratio as pressure proxy
//   B) Polygon 10-day OHLCV+VWAP — accumulation/distribution patterns
//   C) TradingView signal data — volume, VWAP, relative volume
//   D) Options Flow Engine data (upstream) — OI/volume patterns
//
// COMPUTES 8 METRICS:
//   1. Short Volume Ratio + Trend (bearish/bullish pressure)
//   2. VWAP Proximity Score (institutional benchmark trading)
//   3. Accumulation/Distribution Pattern (multi-day analysis)
//   4. Volume Profile Analysis (relative volume, climax detection)
//   5. Price-Volume Divergence (smart money divergence)
//   6. Institutional Momentum Score (composite directional bias)
//   7. Block Trade Proxy (volume clustering analysis)
//   8. Dark Pool Regime (ACCUMULATION, DISTRIBUTION, NEUTRAL, MIXED)
//
// INSERT: After Options Flow Engine, before Perplexity AI Analysis
// ============================================================

// ============================================================
// DATA INPUTS
// ============================================================

// Signal + Options data from upstream (Options Flow Engine)
const ofeItem = $('Options Flow Engine').first();
if (!ofeItem || !ofeItem.json) {
  return [{ json: { dp_error: 'No input from Options Flow Engine' } }];
}
const prev = ofeItem.json;
const ticker = prev.ticker || 'UNKNOWN';

try {

const price = parseFloat(prev.price) || 0;
const signalVol = parseFloat(prev.volume) || 0;
const signalAvgVol = parseFloat(prev.avg_volume) || 0;
const signalVWAP = parseFloat(prev.vwap) || 0;
const relativeVolume = parseFloat(prev.relative_volume) || 0;
const dailyHigh = parseFloat(prev.daily_high) || 0;
const dailyLow = parseFloat(prev.daily_low) || 0;

// FINRA Short Volume data (from Fetch FINRA Short Volume HTTP node)
let finraData = null;
try {
  const finraItems = $('Fetch FINRA Short Volume').all();
  if (finraItems && finraItems.length > 0) {
    const finraRaw = finraItems[0].json;
    // FINRA returns pipe-delimited text as response body
    // HTTP Request node may put it in 'data' or directly in json
    if (typeof finraRaw === 'string') {
      finraData = finraRaw;
    } else if (finraRaw && finraRaw.data) {
      finraData = finraRaw.data;
    } else if (finraRaw && finraRaw.body) {
      finraData = finraRaw.body;  
    } else {
      finraData = finraRaw;
    }
  }
} catch (e) {
  finraData = null;
}

// Polygon 10-day price history (from Fetch Price History HTTP node)
let priceHistory = [];
try {
  const polyItems = $('Fetch Price History').all();
  if (polyItems && polyItems.length > 0) {
    const polyData = polyItems[0].json;
    priceHistory = polyData.results || [];
  }
} catch (e) {
  priceHistory = [];
}

const NL = String.fromCharCode(10);

// ============================================================
// SKIP if no valid price
// ============================================================
if (price <= 0) {
  return [{
    json: {
      ...prev,
      dp_regime: 'NO_PRICE',
      dp_regime_confidence: 'NONE',
      dp_summary: 'No valid price for dark pool analysis',
      dp_short_ratio: 0,
      dp_institutional_score: 0
    }
  }];
}

// ============================================================
// 1. SHORT VOLUME RATIO + TREND
// ============================================================
// FINRA short volume as % of total = institutional pressure proxy
// >45% = heavy shorting (bearish pressure or hedging)
// <35% = light shorting (bullish, institutions not hedging)
// Normal range: 35-45%

let shortRatio = 0;
let shortVolume = 0;
let totalVolume = 0;
let shortSignal = 'UNAVAILABLE';
let shortTrend = 'FLAT';

if (finraData) {
  // Parse FINRA pipe-delimited data
  // Format: Date|Symbol|ShortVolume|ShortExemptVolume|TotalVolume|Market
  let lines = '';
  if (typeof finraData === 'string') {
    lines = finraData;
  } else if (finraData.data && typeof finraData.data === 'string') {
    lines = finraData.data;
  } else if (finraData.body && typeof finraData.body === 'string') {
    lines = finraData.body;
  }

  if (lines) {
    const rows = lines.split(String.fromCharCode(10));
    for (const row of rows) {
      const parts = row.replace(String.fromCharCode(13), '').split('|');
      if (parts.length >= 5 && parts[1] === ticker) {
        shortVolume = parseFloat(parts[2]) || 0;
        totalVolume = parseFloat(parts[4]) || 0;
        if (totalVolume > 0) {
          shortRatio = (shortVolume / totalVolume) * 100;
        }
        break;
      }
    }
  }

  if (shortRatio > 0) {
    if (shortRatio > 50) shortSignal = 'EXTREME_SHORT_PRESSURE';
    else if (shortRatio > 45) shortSignal = 'HIGH_SHORT_PRESSURE';
    else if (shortRatio > 40) shortSignal = 'ELEVATED_SHORTS';
    else if (shortRatio > 35) shortSignal = 'NORMAL';
    else if (shortRatio > 30) shortSignal = 'LOW_SHORTS_BULLISH';
    else shortSignal = 'VERY_LOW_SHORTS_BULLISH';
  }
}

// ============================================================
// 2. VWAP PROXIMITY SCORE
// ============================================================
// Institutional traders benchmark to VWAP
// Price near VWAP = institutional accumulation zone
// Price far above VWAP = retail FOMO (distribution risk)
// Price far below VWAP = capitulation (accumulation opportunity)

let vwapDist = 0;
let vwapSignal = 'UNAVAILABLE';

if (signalVWAP > 0 && price > 0) {
  vwapDist = ((price - signalVWAP) / signalVWAP) * 100;

  if (Math.abs(vwapDist) < 0.3) {
    vwapSignal = 'AT_VWAP';  // Institutional benchmark zone
  } else if (vwapDist > 1.5) {
    vwapSignal = 'EXTENDED_ABOVE';  // Retail FOMO, distribution risk
  } else if (vwapDist > 0.5) {
    vwapSignal = 'ABOVE_VWAP';  // Slight bullish, watching for distribution
  } else if (vwapDist < -1.5) {
    vwapSignal = 'EXTENDED_BELOW';  // Capitulation, accumulation opportunity
  } else if (vwapDist < -0.5) {
    vwapSignal = 'BELOW_VWAP';  // Slight bearish, watching for accumulation
  } else {
    vwapSignal = 'NEAR_VWAP';  // Close to institutional benchmark
  }
}

// ============================================================
// 3. ACCUMULATION / DISTRIBUTION PATTERN (Multi-Day)
// ============================================================
// Analyze 10-day price history for institutional patterns:
// - Accumulation: price flat/down but volume increasing (stealth buying)
// - Distribution: price up but volume declining (institutions selling into strength)
// - Climax: extreme volume + reversal = capitulation/euphoria

let adPattern = 'UNAVAILABLE';
let adScore = 0;  // -100 (heavy distribution) to +100 (heavy accumulation)
let avgHistVol = 0;
let volTrend = 'FLAT';
let priceTrend = 'FLAT';
let closingStrength = 0;  // Where price closes within daily range (0-1)

if (priceHistory.length >= 5) {
  const recent = priceHistory.slice(-5);  // Last 5 days
  const older = priceHistory.slice(0, Math.min(5, priceHistory.length - 5));

  // Volume trend
  const recentAvgVol = recent.reduce((s, r) => s + (r.v || 0), 0) / recent.length;
  const olderAvgVol = older.length > 0
    ? older.reduce((s, r) => s + (r.v || 0), 0) / older.length
    : recentAvgVol;
  avgHistVol = priceHistory.reduce((s, r) => s + (r.v || 0), 0) / priceHistory.length;

  const volChange = olderAvgVol > 0 ? ((recentAvgVol - olderAvgVol) / olderAvgVol) * 100 : 0;
  if (volChange > 20) volTrend = 'INCREASING';
  else if (volChange > 5) volTrend = 'SLIGHTLY_UP';
  else if (volChange < -20) volTrend = 'DECREASING';
  else if (volChange < -5) volTrend = 'SLIGHTLY_DOWN';

  // Price trend (close-to-close over 5 days)
  const firstClose = recent[0].c || 0;
  const lastClose = recent[recent.length - 1].c || 0;
  const priceChange = firstClose > 0 ? ((lastClose - firstClose) / firstClose) * 100 : 0;
  if (priceChange > 2) priceTrend = 'UP';
  else if (priceChange > 0.5) priceTrend = 'SLIGHT_UP';
  else if (priceChange < -2) priceTrend = 'DOWN';
  else if (priceChange < -0.5) priceTrend = 'SLIGHT_DOWN';

  // Closing strength: where today closes within its range
  // High closing strength + high volume = accumulation
  // Low closing strength + high volume = distribution
  const todayBar = recent[recent.length - 1];
  if (todayBar && todayBar.h > todayBar.l) {
    closingStrength = (todayBar.c - todayBar.l) / (todayBar.h - todayBar.l);
  }

  // VWAP deviation trend (are closes converging or diverging from VWAP?)
  let vwapDeviations = recent.filter(r => r.vw > 0).map(r => ((r.c - r.vw) / r.vw) * 100);
  let avgVwapDev = vwapDeviations.length > 0
    ? vwapDeviations.reduce((s, v) => s + v, 0) / vwapDeviations.length
    : 0;

  // Composite accumulation/distribution score
  // Accumulation signals: volume up + price flat/down + high closing strength + close near VWAP
  // Distribution signals: volume down + price up + low closing strength + close far from VWAP

  adScore = 0;

  // Volume increasing while price down = stealth accumulation (+30)
  if (volTrend === 'INCREASING' && (priceTrend === 'DOWN' || priceTrend === 'SLIGHT_DOWN')) {
    adScore += 30;
  }
  // Volume decreasing while price up = distribution (-30)
  else if ((volTrend === 'DECREASING' || volTrend === 'SLIGHTLY_DOWN') && (priceTrend === 'UP' || priceTrend === 'SLIGHT_UP')) {
    adScore -= 30;
  }
  // Volume increasing + price up = confirmed rally (+15)
  else if (volTrend === 'INCREASING' && (priceTrend === 'UP' || priceTrend === 'SLIGHT_UP')) {
    adScore += 15;
  }
  // Volume decreasing + price down = selling exhaustion (+10)
  else if ((volTrend === 'DECREASING' || volTrend === 'SLIGHTLY_DOWN') && (priceTrend === 'DOWN' || priceTrend === 'SLIGHT_DOWN')) {
    adScore += 10;
  }

  // High closing strength = buyers in control (+20)
  if (closingStrength > 0.7) adScore += 20;
  else if (closingStrength < 0.3) adScore -= 20;

  // VWAP proximity = institutional activity (+15)
  if (Math.abs(avgVwapDev) < 0.5) adScore += 15;

  // Short ratio signal
  if (shortRatio > 0) {
    if (shortRatio > 45 && priceTrend !== 'DOWN') adScore -= 15;  // Heavy shorting during rally = distribution
    if (shortRatio < 35) adScore += 10;  // Low shorts = bullish institutional positioning
  }

  // Classify
  if (adScore >= 30) adPattern = 'HEAVY_ACCUMULATION';
  else if (adScore >= 15) adPattern = 'ACCUMULATION';
  else if (adScore >= 5) adPattern = 'SLIGHT_ACCUMULATION';
  else if (adScore <= -30) adPattern = 'HEAVY_DISTRIBUTION';
  else if (adScore <= -15) adPattern = 'DISTRIBUTION';
  else if (adScore <= -5) adPattern = 'SLIGHT_DISTRIBUTION';
  else adPattern = 'NEUTRAL';
}

// ============================================================
// 4. VOLUME PROFILE ANALYSIS
// ============================================================
// Relative volume detects unusual activity
// Volume climax at extremes = reversal signal

let volProfile = 'NORMAL';
let volRatio = 0;

if (signalVol > 0 && signalAvgVol > 0) {
  volRatio = signalVol / signalAvgVol;
} else if (signalVol > 0 && avgHistVol > 0) {
  volRatio = signalVol / avgHistVol;
} else if (relativeVolume > 0) {
  volRatio = relativeVolume;
}

if (volRatio > 3.0) volProfile = 'CLIMAX';        // Extreme volume = potential reversal
else if (volRatio > 2.0) volProfile = 'SURGE';      // Very high = institutional activity
else if (volRatio > 1.5) volProfile = 'ELEVATED';   // Above average = increased interest
else if (volRatio > 0.8) volProfile = 'NORMAL';      // Average range
else if (volRatio > 0) volProfile = 'LOW';          // Below average = quiet accumulation possible

// ============================================================
// 5. PRICE-VOLUME DIVERGENCE
// ============================================================
// Smart money often acts opposite to price:
// Price down + volume surge = capitulation buy opportunity
// Price up + volume dry up = retail-driven, potential trap

let pvDivergence = 'NONE';
if (priceHistory.length >= 3) {
  const last3 = priceHistory.slice(-3);
  const priceDir = last3[last3.length - 1].c > last3[0].c ? 'UP' : 'DOWN';
  const volDir = last3[last3.length - 1].v > last3[0].v ? 'UP' : 'DOWN';

  if (priceDir === 'DOWN' && volDir === 'UP') {
    pvDivergence = 'BULLISH_DIVERGENCE';  // Selling climax, smart money buying
  } else if (priceDir === 'UP' && volDir === 'DOWN') {
    pvDivergence = 'BEARISH_DIVERGENCE';  // Rally on declining volume, distribution
  } else if (priceDir === 'UP' && volDir === 'UP') {
    pvDivergence = 'CONFIRMED_RALLY';     // Volume confirms uptrend
  } else if (priceDir === 'DOWN' && volDir === 'DOWN') {
    pvDivergence = 'SELLING_EXHAUSTION';  // Declining volume on selloff = near bottom
  }
}

// ============================================================
// 6. INSTITUTIONAL MOMENTUM SCORE
// ============================================================
// Composite score: -100 (strong distribution) to +100 (strong accumulation)
// Combines all signals into a single directional bias

let instScore = 0;

// Short volume component (weight: 25%)
if (shortRatio > 0) {
  if (shortRatio > 50) instScore -= 25;
  else if (shortRatio > 45) instScore -= 15;
  else if (shortRatio > 40) instScore -= 5;
  else if (shortRatio < 30) instScore += 25;
  else if (shortRatio < 35) instScore += 15;
  else instScore += 5;  // Normal range, slight positive
}

// A/D pattern component (weight: 25%)
instScore += Math.round(adScore * 0.5);  // Scale adScore (max ~65) to ~25 range

// Volume profile component (weight: 15%)
if (volProfile === 'SURGE' || volProfile === 'CLIMAX') {
  // High volume — direction depends on closing strength
  instScore += closingStrength > 0.5 ? 15 : -15;
} else if (volProfile === 'LOW') {
  instScore -= 5;  // Quiet = slightly negative (no conviction)
}

// VWAP component (weight: 15%)
if (vwapSignal === 'AT_VWAP' || vwapSignal === 'NEAR_VWAP') {
  instScore += 10;  // Near VWAP = institutional zone
} else if (vwapSignal === 'EXTENDED_ABOVE') {
  instScore -= 10;  // Extended above = distribution risk
} else if (vwapSignal === 'EXTENDED_BELOW') {
  instScore += 10;  // Extended below = accumulation opportunity
}

// Price-volume divergence component (weight: 20%)
if (pvDivergence === 'BULLISH_DIVERGENCE') instScore += 20;
else if (pvDivergence === 'BEARISH_DIVERGENCE') instScore -= 20;
else if (pvDivergence === 'CONFIRMED_RALLY') instScore += 10;
else if (pvDivergence === 'SELLING_EXHAUSTION') instScore += 5;

// Clamp to -100..+100
instScore = Math.max(-100, Math.min(100, instScore));

// ============================================================
// 7. BLOCK TRADE PROXY
// ============================================================
// Without direct block trade data, use volume clustering analysis
// Large volume bars that are 2x+ average and close near VWAP = block activity

let blockProxy = 'NONE';
let blockCount = 0;
let blockBias = 'NEUTRAL';

if (priceHistory.length >= 5) {
  const histAvgVol = priceHistory.reduce((s, r) => s + (r.v || 0), 0) / priceHistory.length;

  for (const bar of priceHistory.slice(-5)) {
    if (bar.v > histAvgVol * 2 && bar.vw > 0) {
      const vwapProximity = Math.abs(bar.c - bar.vw) / bar.vw * 100;
      if (vwapProximity < 1.0) {
        blockCount++;
        // Close above VWAP = bullish block, below = bearish
        if (bar.c >= bar.vw) blockBias = 'BULLISH';
        else blockBias = 'BEARISH';
      }
    }
  }

  if (blockCount >= 3) blockProxy = 'HEAVY_BLOCK_ACTIVITY';
  else if (blockCount >= 2) blockProxy = 'MODERATE_BLOCKS';
  else if (blockCount >= 1) blockProxy = 'LIGHT_BLOCKS';
}

// ============================================================
// 8. DARK POOL REGIME — Institutional Decision Tree
// ============================================================
let dpRegime = 'NEUTRAL';
let dpConf = 'LOW';
let dpDetail = '';

// Decision tree combining all signals
if (instScore >= 40) {
  dpRegime = 'STRONG_ACCUMULATION';
  dpConf = 'HIGH';
  dpDetail = 'Multiple signals confirm institutional buying. Smart money is positioning long.';
} else if (instScore >= 20) {
  if (adPattern.includes('ACCUMULATION') && (shortSignal === 'LOW_SHORTS_BULLISH' || shortSignal === 'VERY_LOW_SHORTS_BULLISH')) {
    dpRegime = 'STEALTH_ACCUMULATION';
    dpConf = 'HIGH';
    dpDetail = 'Low short interest + accumulation pattern = institutions quietly building positions.';
  } else {
    dpRegime = 'MODERATE_ACCUMULATION';
    dpConf = 'MODERATE';
    dpDetail = 'Positive institutional flow indicators. Bias toward accumulation.';
  }
} else if (instScore <= -40) {
  dpRegime = 'STRONG_DISTRIBUTION';
  dpConf = 'HIGH';
  dpDetail = 'Multiple signals confirm institutional selling. Smart money is exiting or shorting.';
} else if (instScore <= -20) {
  if (adPattern.includes('DISTRIBUTION') && shortSignal.includes('SHORT_PRESSURE')) {
    dpRegime = 'ACTIVE_DISTRIBUTION';
    dpConf = 'HIGH';
    dpDetail = 'High short pressure + distribution pattern = institutions actively selling.';
  } else {
    dpRegime = 'MODERATE_DISTRIBUTION';
    dpConf = 'MODERATE';
    dpDetail = 'Negative institutional flow indicators. Bias toward distribution.';
  }
} else {
  // Mixed or neutral
  if (pvDivergence === 'BULLISH_DIVERGENCE') {
    dpRegime = 'CONTRARIAN_ACCUMULATION';
    dpConf = 'MODERATE';
    dpDetail = 'Price-volume divergence suggests smart money buying into weakness.';
  } else if (pvDivergence === 'BEARISH_DIVERGENCE') {
    dpRegime = 'STEALTH_DISTRIBUTION';
    dpConf = 'MODERATE';
    dpDetail = 'Price-volume divergence suggests smart money selling into strength.';
  } else {
    dpRegime = 'NEUTRAL';
    dpConf = 'LOW';
    dpDetail = 'No clear institutional directional bias detected.';
  }
}

// Cross-reference with options flow regime
const optRegime = prev.opt_regime || '';
if (optRegime === 'CONTRARIAN_LONG' && dpRegime.includes('ACCUMULATION')) {
  dpConf = 'VERY_HIGH';
  dpDetail += ' OPTIONS CONFIRM: Contrarian long + accumulation = strong institutional conviction.';
} else if (optRegime === 'GAMMA_SQUEEZE_DOWN' && dpRegime.includes('DISTRIBUTION')) {
  dpConf = 'VERY_HIGH';
  dpDetail += ' OPTIONS CONFIRM: Gamma squeeze down + distribution = cascading institutional exit.';
} else if (optRegime.includes('UP') && dpRegime.includes('DISTRIBUTION')) {
  dpDetail += ' CAUTION: Options bullish but institutional flow shows distribution. Watch for trap.';
} else if (optRegime.includes('DOWN') && dpRegime.includes('ACCUMULATION')) {
  dpDetail += ' CAUTION: Options bearish but institutional flow shows accumulation. Potential reversal.';
}

// Block trade overlay
if (blockProxy === 'HEAVY_BLOCK_ACTIVITY') {
  dpDetail += ' Block activity detected (' + blockCount + ' sessions with 2x+ volume at VWAP).';
  if (dpConf === 'MODERATE') dpConf = 'HIGH';
}

// ============================================================
// BUILD SUMMARY TEXT for Telegram
// ============================================================
let sum = '';
sum += 'Short Ratio: ' + (shortRatio > 0 ? shortRatio.toFixed(1) + '% | ' + shortSignal : 'Unavailable');
sum += NL + 'VWAP Proximity: ' + (vwapDist !== 0 ? vwapDist.toFixed(2) + '% | ' + vwapSignal : 'Unavailable');
sum += NL + 'A/D Pattern: ' + adPattern + ' (score: ' + adScore + ')';
sum += NL + 'Volume: ' + volProfile + (volRatio > 0 ? ' (' + (volRatio * 100).toFixed(0) + '% of avg)' : '');
sum += NL + 'P/V Divergence: ' + pvDivergence;
if (blockProxy !== 'NONE') {
  sum += NL + 'Block Proxy: ' + blockProxy + ' (' + blockCount + ' sessions, ' + blockBias + ')';
}
sum += NL + 'Inst. Score: ' + instScore + '/100';
sum += NL + 'REGIME: ' + dpRegime + ' (' + dpConf + ')';
sum += NL + dpDetail;

// ============================================================
// OUTPUT
// ============================================================
return [{
  json: {
    ...prev,

    // Flat fields for Perplexity prompt expressions
    dp_short_ratio: shortRatio > 0 ? shortRatio.toFixed(1) + '%' : 'N/A',
    dp_short_signal: shortSignal,
    dp_short_volume: shortVolume > 0 ? Math.round(shortVolume).toLocaleString() : 'N/A',
    dp_vwap_dist: vwapDist !== 0 ? vwapDist.toFixed(2) + '%' : 'N/A',
    dp_vwap_signal: vwapSignal,
    dp_ad_pattern: adPattern,
    dp_ad_score: adScore,
    dp_vol_profile: volProfile,
    dp_vol_ratio: volRatio > 0 ? (volRatio * 100).toFixed(0) + '%' : 'N/A',
    dp_pv_divergence: pvDivergence,
    dp_closing_strength: closingStrength > 0 ? (closingStrength * 100).toFixed(0) + '%' : 'N/A',
    dp_block_proxy: blockProxy,
    dp_block_count: blockCount,
    dp_block_bias: blockBias,
    dp_institutional_score: instScore,
    dp_regime: dpRegime,
    dp_regime_confidence: dpConf,
    dp_regime_detail: dpDetail,
    dp_price_trend: priceTrend,
    dp_vol_trend: volTrend,

    // Full summary for Telegram format node
    dp_summary: sum
  }
}];


} catch (engineError) {
  return [{
    json: {
      ...prev,
      dp_regime: 'ERROR',
      dp_regime_confidence: 'NONE',
      dp_summary: 'Dark pool engine error: ' + (engineError.message || 'unknown'),
      dp_error: engineError.message || 'Dark Pool Engine failed',
      dp_institutional_score: 0,
    }
  }];
}

// ============================================================
// CROSS-ASSET CORRELATION ENGINE v1 — Phase 2.4
// Quantum Engineering Trading Pipeline
//
// PURPOSE: Enriches every signal with macro context from
// 12 cross-asset instruments. Computes correlation scores,
// risk-on/risk-off regime, sector rotation signals, and
// VIX term structure (contango/backwardation proxy).
//
// DATA SOURCES:
// 1. TradingView webhook (already in payload): SPY, QQQ, VIX, XLY
// 2. Polygon grouped-daily (new): XLK, XLF, XLE, XLV, TLT, UUP,
//    HYG, GLD, IWM, DIA, VIXY, VIXM, IEF
// 3. Polygon grouped-daily (previous day): same tickers for % change
//
// INSERT: After Dark Pool Engine, before Perplexity AI
// READS FROM: $('Dark Pool Engine') for signal data
//             $('Fetch Cross-Asset Today') for today's bars
//             $('Fetch Cross-Asset Previous') for yesterday's bars
// ============================================================

const prev = $('Dark Pool Engine').first().json;
const ticker = prev.ticker || 'UNKNOWN';
const price = prev.price || 0;

try {
// ---- BEGIN MAIN LOGIC (wrapped in try-catch to preserve passthrough on error) ----

// ============================================================
// PARSE GROUPED DAILY DATA — extract target ETFs from bulk response
// ============================================================
let todayData = {};
let prevData = {};

try {
  const todayRaw = $('Fetch Cross-Asset Today').first().json;
  const todayResults = todayRaw.results || [];
  const TARGETS = ['SPY','QQQ','XLK','XLY','XLF','XLE','XLV','TLT','UUP','HYG','GLD','IWM','DIA','VIXY','VIXM','IEF'];
  for (const bar of todayResults) {
    if (TARGETS.includes(bar.T)) {
      todayData[bar.T] = { o: bar.o, h: bar.h, l: bar.l, c: bar.c, v: bar.v, vw: bar.vw };
    }
  }
} catch(e) { /* grouped endpoint may fail — use webhook data as fallback */ }

try {
  const prevRaw = $('Fetch Cross-Asset Previous').first().json;
  const prevResults = prevRaw.results || [];
  const TARGETS = ['SPY','QQQ','XLK','XLY','XLF','XLE','XLV','TLT','UUP','HYG','GLD','IWM','DIA','VIXY','VIXM','IEF'];
  for (const bar of prevResults) {
    if (TARGETS.includes(bar.T)) {
      prevData[bar.T] = { o: bar.o, h: bar.h, l: bar.l, c: bar.c, v: bar.v, vw: bar.vw };
    }
  }
} catch(e) { /* use available data */ }

// ============================================================
// HELPER: Calculate % change between two days
// ============================================================
function pctChange(sym) {
  const today = todayData[sym];
  const yesterday = prevData[sym];
  if (!today || !yesterday || !yesterday.c) return null;
  return ((today.c - yesterday.c) / yesterday.c) * 100;
}

function todayClose(sym) {
  return todayData[sym] ? todayData[sym].c : null;
}

function todayOC(sym) {
  // Open-to-close change (intraday direction)
  const d = todayData[sym];
  if (!d || !d.o) return null;
  return ((d.c - d.o) / d.o) * 100;
}

// ============================================================
// METRIC 1: BROAD MARKET HEALTH (SPY + QQQ + DIA + IWM)
// Weight: 25% of correlation score
// ============================================================
const spyChg = pctChange('SPY');
const qqqChg = pctChange('QQQ');
const diaChg = pctChange('DIA');
const iwmChg = pctChange('IWM');

// Use webhook data as primary for SPY/QQQ if Polygon unavailable
const spyFinal = spyChg !== null ? spyChg : parseFloat(prev.spy_change_pct) || 0;
const qqqFinal = qqqChg !== null ? qqqChg : parseFloat(prev.qqq_change_pct) || 0;
const diaFinal = diaChg !== null ? diaChg : 0;
const iwmFinal = iwmChg !== null ? iwmChg : 0;

// Breadth score: average of 4 major indices
const breadthAvg = (spyFinal + qqqFinal + diaFinal + iwmFinal) / 4;
const allUp = spyFinal > 0 && qqqFinal > 0 && diaFinal > 0 && iwmFinal > 0;
const allDown = spyFinal < 0 && qqqFinal < 0 && diaFinal < 0 && iwmFinal < 0;

let broadHealth = 'MIXED';
let broadScore = 50; // neutral
if (allUp && breadthAvg > 0.5) { broadHealth = 'RISK_ON'; broadScore = 80; }
else if (allUp) { broadHealth = 'MILDLY_BULLISH'; broadScore = 65; }
else if (allDown && breadthAvg < -0.5) { broadHealth = 'RISK_OFF'; broadScore = 20; }
else if (allDown) { broadHealth = 'MILDLY_BEARISH'; broadScore = 35; }
else if (Math.abs(spyFinal - iwmFinal) > 1.5) { broadHealth = 'ROTATION'; broadScore = 45; }

// ============================================================
// METRIC 2: VIX TERM STRUCTURE (VIXY vs VIXM proxy)
// Weight: 15%
// Contango (VIXY losing relative to VIXM) = normal/complacent
// Backwardation (VIXY outperforming VIXM) = panic/hedging
// ============================================================
const vixyChg = pctChange('VIXY');
const vixmChg = pctChange('VIXM');
const vixFromWebhook = prev.vix || 0;

let vixTermStructure = 'UNKNOWN';
let vixTermScore = 50;
let vixTermDetail = '';

if (vixyChg !== null && vixmChg !== null) {
  const spread = vixyChg - vixmChg; // positive = backwardation (panic)
  if (spread > 3) {
    vixTermStructure = 'STEEP_BACKWARDATION';
    vixTermScore = 10;
    vixTermDetail = 'Extreme fear — front-month vol surging vs mid-term';
  } else if (spread > 1) {
    vixTermStructure = 'BACKWARDATION';
    vixTermScore = 25;
    vixTermDetail = 'Hedging demand elevated — institutional protection buying';
  } else if (spread > -1) {
    vixTermStructure = 'FLAT';
    vixTermScore = 50;
    vixTermDetail = 'Neutral term structure — no clear vol signal';
  } else if (spread > -3) {
    vixTermStructure = 'CONTANGO';
    vixTermScore = 70;
    vixTermDetail = 'Normal conditions — vol sellers in control';
  } else {
    vixTermStructure = 'STEEP_CONTANGO';
    vixTermScore = 85;
    vixTermDetail = 'Complacent — low near-term fear, potential for vol spike';
  }
} else if (vixFromWebhook > 0) {
  // Fallback: use absolute VIX level
  if (vixFromWebhook > 35) { vixTermStructure = 'EXTREME'; vixTermScore = 5; vixTermDetail = 'Crisis-level VIX'; }
  else if (vixFromWebhook > 25) { vixTermStructure = 'ELEVATED'; vixTermScore = 25; vixTermDetail = 'High VIX — defensive posture'; }
  else if (vixFromWebhook > 18) { vixTermStructure = 'NORMAL'; vixTermScore = 55; vixTermDetail = 'VIX in normal range'; }
  else { vixTermStructure = 'LOW'; vixTermScore = 80; vixTermDetail = 'Low VIX — favorable for risk-on'; }
}

// ============================================================
// METRIC 3: DOLLAR STRENGTH (UUP proxy for DXY)
// Weight: 10%
// Strong dollar = headwind for multinationals (TSLA, AAPL)
// Weak dollar = tailwind for exporters, commodities, EM
// ============================================================
const uupChg = pctChange('UUP');
let dollarTrend = 'NEUTRAL';
let dollarScore = 50;
let dollarImpact = '';

if (uupChg !== null) {
  if (uupChg > 0.5) { dollarTrend = 'STRENGTHENING'; dollarScore = 35; dollarImpact = 'Headwind for exporters/multinationals'; }
  else if (uupChg > 0.15) { dollarTrend = 'MILDLY_STRONG'; dollarScore = 45; dollarImpact = 'Slight headwind'; }
  else if (uupChg < -0.5) { dollarTrend = 'WEAKENING'; dollarScore = 70; dollarImpact = 'Tailwind for exporters/commodities'; }
  else if (uupChg < -0.15) { dollarTrend = 'MILDLY_WEAK'; dollarScore = 60; dollarImpact = 'Slight tailwind'; }
  else { dollarTrend = 'STABLE'; dollarScore = 55; dollarImpact = 'No directional pressure'; }
}

// ============================================================
// METRIC 4: INTEREST RATE SENSITIVITY (TLT + IEF)
// Weight: 10%
// TLT down = yields up = headwind for growth/tech
// TLT up = yields down = tailwind for growth/tech
// ============================================================
const tltChg = pctChange('TLT');
const iefChg = pctChange('IEF');

let yieldTrend = 'NEUTRAL';
let yieldScore = 50;
let yieldImpact = '';

const bondAvg = (tltChg !== null && iefChg !== null) ? (tltChg + iefChg) / 2
  : tltChg !== null ? tltChg : iefChg;

if (bondAvg !== null) {
  if (bondAvg < -1.0) { yieldTrend = 'YIELDS_SURGING'; yieldScore = 20; yieldImpact = 'Strong headwind for growth/tech stocks'; }
  else if (bondAvg < -0.3) { yieldTrend = 'YIELDS_RISING'; yieldScore = 35; yieldImpact = 'Headwind for rate-sensitive stocks'; }
  else if (bondAvg > 1.0) { yieldTrend = 'YIELDS_PLUNGING'; yieldScore = 80; yieldImpact = 'Strong flight-to-safety — bullish for long-duration'; }
  else if (bondAvg > 0.3) { yieldTrend = 'YIELDS_FALLING'; yieldScore = 65; yieldImpact = 'Tailwind for growth/tech stocks'; }
  else { yieldTrend = 'STABLE'; yieldScore = 55; yieldImpact = 'No rate pressure'; }
}

// ============================================================
// METRIC 5: SECTOR ROTATION (XLK, XLY, XLF, XLE, XLV vs SPY)
// Weight: 15%
// Maps ticker to its sector ETF for relative strength
// ============================================================
const sectorMap = {
  'TSLA': 'XLY', 'AMZN': 'XLY', 'MCD': 'XLY', 'NKE': 'XLY', 'HD': 'XLY',
  'NVDA': 'XLK', 'AMD': 'XLK', 'MSFT': 'XLK', 'AAPL': 'XLK', 'CRWV': 'XLK', 'NBIS': 'XLK', 'GOOG': 'XLK', 'META': 'XLK',
  'JPM': 'XLF', 'GS': 'XLF', 'BAC': 'XLF', 'C': 'XLF',
  'XOM': 'XLE', 'CVX': 'XLE', 'SLB': 'XLE',
  'GILD': 'XLV', 'JNJ': 'XLV', 'PFE': 'XLV', 'UNH': 'XLV', 'LLY': 'XLV',
};

const tickerSector = sectorMap[ticker] || 'XLK'; // default to tech
const sectorChg = pctChange(tickerSector);
const sectorVsSPY = (sectorChg !== null && spyFinal !== null) ? sectorChg - spyFinal : null;

let sectorRotation = 'NEUTRAL';
let sectorScore = 50;
let sectorDetail = '';

if (sectorVsSPY !== null) {
  if (sectorVsSPY > 1.0) { sectorRotation = 'SECTOR_LEADING'; sectorScore = 80; sectorDetail = tickerSector + ' outperforming SPY by ' + sectorVsSPY.toFixed(1) + '%'; }
  else if (sectorVsSPY > 0.3) { sectorRotation = 'SECTOR_STRONG'; sectorScore = 65; sectorDetail = tickerSector + ' slightly leading SPY'; }
  else if (sectorVsSPY < -1.0) { sectorRotation = 'SECTOR_LAGGING'; sectorScore = 20; sectorDetail = tickerSector + ' underperforming SPY by ' + Math.abs(sectorVsSPY).toFixed(1) + '%'; }
  else if (sectorVsSPY < -0.3) { sectorRotation = 'SECTOR_WEAK'; sectorScore = 35; sectorDetail = tickerSector + ' slightly lagging SPY'; }
  else { sectorRotation = 'INLINE'; sectorScore = 55; sectorDetail = tickerSector + ' tracking SPY'; }
}

// ============================================================
// METRIC 6: CREDIT / RISK APPETITE (HYG high-yield vs GLD gold)
// Weight: 10%
// HYG up + GLD down = risk-on (credit appetite)
// HYG down + GLD up = risk-off (flight to safety)
// ============================================================
const hygChg = pctChange('HYG');
const gldChg = pctChange('GLD');

let riskAppetite = 'NEUTRAL';
let riskScore = 50;
let riskDetail = '';

if (hygChg !== null && gldChg !== null) {
  const riskSpread = hygChg - gldChg; // positive = risk-on
  if (riskSpread > 1.0) { riskAppetite = 'STRONG_RISK_ON'; riskScore = 85; riskDetail = 'Credit rallying, gold falling — aggressive risk appetite'; }
  else if (riskSpread > 0.3) { riskAppetite = 'MILD_RISK_ON'; riskScore = 65; riskDetail = 'Credit outperforming gold — constructive'; }
  else if (riskSpread < -1.0) { riskAppetite = 'STRONG_RISK_OFF'; riskScore = 15; riskDetail = 'Gold rallying, credit falling — flight to safety'; }
  else if (riskSpread < -0.3) { riskAppetite = 'MILD_RISK_OFF'; riskScore = 35; riskDetail = 'Gold outperforming credit — defensive posture'; }
  else { riskAppetite = 'BALANCED'; riskScore = 55; riskDetail = 'No clear risk appetite signal'; }
} else if (gldChg !== null) {
  if (gldChg > 1.0) { riskAppetite = 'GOLD_BID'; riskScore = 30; riskDetail = 'Gold surging — safe-haven demand'; }
  else if (gldChg < -1.0) { riskAppetite = 'GOLD_SOLD'; riskScore = 70; riskDetail = 'Gold sold off — risk appetite returning'; }
}

// ============================================================
// METRIC 7: SMALL CAP vs LARGE CAP DIVERGENCE (IWM vs SPY)
// Weight: 5%
// IWM leading = broad risk-on, domestic focus
// IWM lagging = narrow leadership, fragile rally
// ============================================================
const iwmVsSpy = (typeof iwmFinal === 'number' && typeof spyFinal === 'number') ? iwmFinal - spyFinal : null;
let capRotation = 'NEUTRAL';
let capScore = 50;

if (iwmVsSpy !== null) {
  if (iwmVsSpy > 1.0) { capRotation = 'SMALLS_LEADING'; capScore = 75; }
  else if (iwmVsSpy > 0.3) { capRotation = 'SMALLS_STRONG'; capScore = 60; }
  else if (iwmVsSpy < -1.0) { capRotation = 'SMALLS_LAGGING'; capScore = 25; }
  else if (iwmVsSpy < -0.3) { capRotation = 'SMALLS_WEAK'; capScore = 40; }
}

// ============================================================
// METRIC 8: NVDA AS AI BELLWETHER (for AI/tech tickers)
// Weight: 10% (only for CRWV, NBIS, AMD, and AI-adjacent)
// ============================================================
const aiTickers = ['CRWV', 'NBIS', 'AMD', 'NVDA', 'MSFT', 'GOOG', 'META', 'SMCI', 'ARM', 'AVGO'];
const isAITicker = aiTickers.includes(ticker);
const nvdaChg = pctChange('NVDA') || null; // NVDA may not be in grouped (only if traded)
let aiBellwether = 'N/A';
let aiScore = 50;

// For NVDA itself, skip self-comparison
if (isAITicker && ticker !== 'NVDA') {
  // Try to get NVDA from today's data (may not be in the grouped ETF response)
  // Fall back to XLK (tech sector) as proxy
  const proxy = nvdaChg !== null ? nvdaChg : (pctChange('XLK') || 0);
  if (proxy > 1.5) { aiBellwether = 'AI_BULL'; aiScore = 80; }
  else if (proxy > 0.3) { aiBellwether = 'AI_CONSTRUCTIVE'; aiScore = 65; }
  else if (proxy < -1.5) { aiBellwether = 'AI_BEAR'; aiScore = 20; }
  else if (proxy < -0.3) { aiBellwether = 'AI_CAUTIOUS'; aiScore = 35; }
  else { aiBellwether = 'AI_NEUTRAL'; aiScore = 50; }
}

// ============================================================
// COMPOSITE CROSS-ASSET SCORE (0-100)
// Weighted average of all metrics
// ============================================================
const weights = {
  broad: 0.25,
  vixTerm: 0.15,
  dollar: 0.10,
  yields: 0.10,
  sector: 0.15,
  risk: 0.10,
  caps: 0.05,
  ai: isAITicker && ticker !== 'NVDA' ? 0.10 : 0
};

// Normalize weights (AI weight only for AI tickers)
const totalWeight = Object.values(weights).reduce((a, b) => a + b, 0);
const normFactor = 1 / totalWeight;

const compositeScore = Math.round(
  (broadScore * weights.broad +
   vixTermScore * weights.vixTerm +
   dollarScore * weights.dollar +
   yieldScore * weights.yields +
   sectorScore * weights.sector +
   riskScore * weights.risk +
   capScore * weights.caps +
   aiScore * weights.ai) * normFactor
);

// ============================================================
// CROSS-ASSET REGIME CLASSIFICATION
// ============================================================
let caRegime = 'NEUTRAL';
let caRegimeConfidence = 'LOW';
let caRegimeDetail = '';

if (compositeScore >= 75) {
  caRegime = 'STRONG_RISK_ON';
  caRegimeConfidence = 'HIGH';
  caRegimeDetail = 'Broad market, sector, credit, and vol all supportive';
} else if (compositeScore >= 60) {
  caRegime = 'MILD_RISK_ON';
  caRegimeConfidence = 'MODERATE';
  caRegimeDetail = 'Generally constructive macro backdrop';
} else if (compositeScore <= 25) {
  caRegime = 'CRISIS';
  caRegimeConfidence = 'HIGH';
  caRegimeDetail = 'Multiple macro headwinds — capital preservation mode';
} else if (compositeScore <= 40) {
  caRegime = 'RISK_OFF';
  caRegimeConfidence = 'MODERATE';
  caRegimeDetail = 'Defensive conditions — reduce exposure';
} else {
  caRegime = 'MIXED';
  caRegimeConfidence = 'LOW';
  caRegimeDetail = 'Conflicting cross-asset signals — selective positioning';
}

// ============================================================
// SIGNAL ALIGNMENT CHECK
// Does cross-asset environment support the signal direction?
// ============================================================
const signalDir = (prev.signal || '').toUpperCase();
const isBullish = signalDir === 'BULLISH' || (prev.execution || '').toUpperCase() === 'BUY' || (prev.execution || '').toUpperCase() === 'SCALE IN';
const isBearish = signalDir === 'BEARISH' || (prev.execution || '').toUpperCase() === 'SELL';

let signalAlignment = 'NEUTRAL';
let alignmentAdjust = 0;

if (isBullish) {
  if (compositeScore >= 65) { signalAlignment = 'CONFIRMED'; alignmentAdjust = +1; }
  else if (compositeScore >= 50) { signalAlignment = 'CAUTIOUS'; alignmentAdjust = 0; }
  else if (compositeScore >= 35) { signalAlignment = 'DIVERGENT'; alignmentAdjust = -1; }
  else { signalAlignment = 'HOSTILE'; alignmentAdjust = -2; }
} else if (isBearish) {
  // For bearish signals, low composite = confirming
  if (compositeScore <= 35) { signalAlignment = 'CONFIRMED'; alignmentAdjust = +1; }
  else if (compositeScore <= 50) { signalAlignment = 'CAUTIOUS'; alignmentAdjust = 0; }
  else if (compositeScore <= 65) { signalAlignment = 'DIVERGENT'; alignmentAdjust = -1; }
  else { signalAlignment = 'HOSTILE'; alignmentAdjust = -2; }
}

// ============================================================
// BUILD SUMMARY STRING (for Telegram display)
// ============================================================
const NL = String.fromCharCode(10);
let summary = 'CROSS-ASSET: ' + caRegime + ' (Score: ' + compositeScore + '/100, ' + caRegimeConfidence + ')' + NL;
summary += 'Market: ' + broadHealth + ' (SPY ' + (typeof spyFinal === 'number' ? spyFinal.toFixed(1) : spyFinal) + '%, QQQ ' + (typeof qqqFinal === 'number' ? qqqFinal.toFixed(1) : qqqFinal) + '%, IWM ' + (iwmFinal ? iwmFinal.toFixed(1) : '?') + '%, DIA ' + (diaFinal ? diaFinal.toFixed(1) : '?') + '%)' + NL;
summary += 'VIX Term: ' + vixTermStructure + (vixFromWebhook ? ' (VIX ' + vixFromWebhook + ')' : '') + NL;
summary += 'Dollar: ' + dollarTrend + (uupChg !== null ? ' (UUP ' + uupChg.toFixed(2) + '%)' : '') + NL;
summary += 'Yields: ' + yieldTrend + (tltChg !== null ? ' (TLT ' + tltChg.toFixed(2) + '%)' : '') + NL;
summary += 'Sector: ' + sectorRotation + ' (' + sectorDetail + ')' + NL;
summary += 'Credit/Gold: ' + riskAppetite + NL;
if (isAITicker && ticker !== 'NVDA') {
  summary += 'AI Bellwether: ' + aiBellwether + NL;
}
summary += 'Signal Align: ' + signalAlignment + ' (adjust ' + (alignmentAdjust >= 0 ? '+' : '') + alignmentAdjust + ')';

// ============================================================
// OUTPUT — pass everything downstream
// ============================================================
return [{
  json: {
    ...prev,

    // Cross-Asset Correlation Engine outputs
    ca_composite_score: compositeScore,
    ca_regime: caRegime,
    ca_regime_confidence: caRegimeConfidence,
    ca_regime_detail: caRegimeDetail,
    ca_signal_alignment: signalAlignment,
    ca_alignment_adjust: alignmentAdjust,
    ca_summary: summary,

    // Individual metrics (for Perplexity analysis)
    ca_broad_health: broadHealth,
    ca_broad_score: broadScore,
    ca_spy_chg: spyFinal ? +spyFinal.toFixed(2) : 0,
    ca_qqq_chg: qqqFinal ? +qqqFinal.toFixed(2) : 0,
    ca_iwm_chg: iwmFinal ? +iwmFinal.toFixed(2) : 0,
    ca_dia_chg: diaFinal ? +diaFinal.toFixed(2) : 0,
    ca_vix_term: vixTermStructure,
    ca_vix_term_detail: vixTermDetail,
    ca_dollar_trend: dollarTrend,
    ca_dollar_impact: dollarImpact,
    ca_yield_trend: yieldTrend,
    ca_yield_impact: yieldImpact,
    ca_sector_rotation: sectorRotation,
    ca_sector_detail: sectorDetail,
    ca_sector_etf: tickerSector,
    ca_risk_appetite: riskAppetite,
    ca_risk_detail: riskDetail,
    ca_cap_rotation: capRotation,
    ca_ai_bellwether: isAITicker ? aiBellwether : 'N/A',

    // Raw changes (for Perplexity to reference)
    ca_tlt_chg: tltChg !== null ? +tltChg.toFixed(2) : null,
    ca_uup_chg: uupChg !== null ? +uupChg.toFixed(2) : null,
    ca_hyg_chg: hygChg !== null ? +hygChg.toFixed(2) : null,
    ca_gld_chg: gldChg !== null ? +gldChg.toFixed(2) : null,
    ca_xlk_chg: pctChange('XLK') !== null ? +pctChange('XLK').toFixed(2) : null,
    ca_xly_chg: pctChange('XLY') !== null ? +pctChange('XLY').toFixed(2) : null,
    ca_xlf_chg: pctChange('XLF') !== null ? +pctChange('XLF').toFixed(2) : null,
    ca_xle_chg: pctChange('XLE') !== null ? +pctChange('XLE').toFixed(2) : null,
    ca_xlv_chg: pctChange('XLV') !== null ? +pctChange('XLV').toFixed(2) : null,
  }
}];

} catch (engineError) {
  // FALLBACK: If Cross-Asset Engine crashes, preserve ALL passthrough fields
  // so Format Telegram Message still gets ticker, price, timeframe etc.
  return [{
    json: {
      ...prev,
      ca_error: engineError.message || 'Cross-Asset Engine failed',
      ca_composite_score: 50,
      ca_regime: 'UNAVAILABLE',
      ca_regime_confidence: 'LOW',
      ca_signal_alignment: 'NEUTRAL',
      ca_alignment_adjust: 0,
      ca_summary: 'CROSS-ASSET: UNAVAILABLE (engine error: ' + (engineError.message || 'unknown') + ')',
    }
  }];
}

// Alpaca Paper Trade v4.4 — H-2 limit order entry — C-6 notional cap final guard — GTC fix for bracket orders — Position Sizing + Native Bracket Orders + Slip-Proof Stops
// v4.4: LIMIT ORDER ENTRY — Replace market orders with limit orders to reduce slippage
//       Fetches NBBO quote from Alpaca Data API, places limit at ask+1tick for buys
//       Wide-spread guard: if spread > 0.5% of mid, use mid+1tick instead of chasing ask
//       Fallback: market order if Data API unreachable (position protection > slippage savings)
//       Bracket orders: entry type='limit' with limit_price, TIF stays 'gtc'
//       Volatile trail path: limit + IOC, auto-fallback to market if IOC cancelled
// v4.3: C-6 notional cap final guard
// v4.1: Compute qty from eff_position_size × vix_size_mult × portfolio_value / price
//       Falls back to order_qty/qty/1 if sizing data unavailable
// Fix 1: Use Alpaca order_class='bracket' — stop and target are natively linked (real OCO).
//         Pre-bracket cancel sweep removed — no more orphaned legs.
// Fix 2: Stop buffer = max($0.10, 0.1% of price) for non-volatile; 0.2% for volatile.
//         Volatile names with trailing stop unaffected (no limit leg needed).

const prev    = $input.first().json;
const ticker  = (prev.ticker || '').toUpperCase();
const execution = (prev.execution || prev._sm_route || '').toUpperCase();
const signal  = (prev.signal || '').toUpperCase();

const _creds       = $getWorkflowStaticData('global');
const ALPACA_KEY   = _creds._alpaca_key    || 'REDACTED_ALPACA_KEY_ID';
const ALPACA_SEC   = _creds._alpaca_secret || 'REDACTED_ALPACA_SECRET';
const BASE         = 'https://paper-api.alpaca.markets';
const DATA_BASE    = 'https://data.alpaca.markets/v2';
const HDR          = {
  'APCA-API-KEY-ID':    ALPACA_KEY,
  'APCA-API-SECRET-KEY': ALPACA_SEC,
  'Content-Type':       'application/json'
};

const VOLATILE  = new Set(['SQQQ','TQQQ','SPXS','SPXL','SOXS','SOXL','UVXY','SVXY','SMCI','IONQ']);
const vol       = VOLATILE.has(ticker);
const SL_MULT   = vol ? 1.0 : 1.5;
const TRAIL_PCT = vol ? '3' : null;

const TICK = 0.01;                  // SEC Rule 612: min increment for stocks >= $1
const SPREAD_WARN_PCT = 0.005;      // 0.5% — wide spread threshold

const isEntry = ['BUY','SELL','BULLISH','BEARISH','LONG','SHORT'].includes(execution) ||
                ['BUY','SELL','BULLISH','BEARISH'].includes(signal);
if (!isEntry || !ticker) {
  return [{ json: { ...prev, alpaca_status: 'SKIPPED', alpaca_reason: 'Not an entry signal' } }];
}
if (ticker === 'SPY' || ticker === 'QQQ') {
  return [{ json: { ...prev, alpaca_status: 'SKIPPED', alpaca_reason: 'Index — monitor only' } }];
}

// ── v3.1 DEDUP GUARD — unchanged, still needed ───────────────────────────────
const _aptState = $getWorkflowStaticData('global');
if (!_aptState._aptDedup) _aptState._aptDedup = {};
const _dedupKey = ticker + '_' + (prev.timeframe || '5');
const _lastTradeMs = _aptState._aptDedup[_dedupKey] || 0;
if (Date.now() - _lastTradeMs < 90000) {
  console.log('[APT v4.4] DEDUP — already traded ' + ticker + ' within 90s, skipping duplicate');
  return [{ json: { ...prev, alpaca_status: 'SKIPPED', alpaca_reason: 'Dedup: already traded within 90s' } }];
}
_aptState._aptDedup[_dedupKey] = Date.now();
for (const k of Object.keys(_aptState._aptDedup)) {
  if (Date.now() - _aptState._aptDedup[k] > 300000) delete _aptState._aptDedup[k];
}
// ─────────────────────────────────────────────────────────────────────────────

const isLong    = ['BUY','BULLISH','LONG'].includes(execution) || ['BUY','BULLISH'].includes(signal);
const side      = isLong ? 'buy' : 'sell';
const closeSide = isLong ? 'sell' : 'buy';

const price  = parseFloat(prev.price || 0);
const atrRaw = parseFloat(prev.atr   || prev.atr_est || 0);
const atr    = atrRaw > 0 ? atrRaw : price * 0.015;

// ── v4.1: Position sizing from SM eff_position_size × vix_size_mult ─────────
let qty;
const effPct    = parseFloat(prev.eff_position_size || 0);
const vixMult   = parseFloat(prev.vix_size_mult || 1);
const explicitQ = parseInt(prev.order_qty || prev.qty || 0);

if (explicitQ > 0) {
  qty = explicitQ;
  console.log(`[APT v4.4] Using explicit qty=${qty}`);
} else if (effPct > 0 && price > 0) {
  let portfolioValue = 100000;
  try {
    const acct = await this.helpers.httpRequest({
      method: 'GET', url: BASE + '/v2/account', headers: HDR, json: true
    });
    portfolioValue = parseFloat(acct.portfolio_value || acct.equity || 100000);
  } catch (e) {
    console.warn('[APT v4.4] Account fetch failed, using default $100k:', e.message);
  }
  const notional = portfolioValue * (effPct / 100) * vixMult;
  qty = Math.max(1, Math.floor(notional / price));
  console.log(`[APT v4.4] Sized: portfolio=$${portfolioValue} × ${effPct}% × ${vixMult} = $${notional.toFixed(0)} / $${price} = ${qty} shares`);
} else {
  qty = 1;
  console.log(`[APT v4.4] Fallback qty=1 (effPct=${effPct}, price=${price})`);
}
// ─────────────────────────────────────────────────────────────────────────────

const r2 = n => Math.round(n * 100) / 100;

// ── C-6 FINAL GUARD: Notional cap enforcement (last line of defense) ────────
const _smClampedQty = parseInt(prev._sm_sizer_clamped_qty || 0);
const _smSizerAllowed = prev._sm_sizer_allowed;

if (_smSizerAllowed === false) {
  console.log('[APT v4.4] BLOCKED by position sizer: ' + (prev._sm_sizer_blocks || 'unknown'));
  return [{ json: { ...prev, alpaca_status: 'BLOCKED', alpaca_reason: 'Position sizer: ' + (prev._sm_sizer_blocks || 'cap exceeded') } }];
}

if (_smClampedQty > 0 && _smClampedQty < qty) {
  console.log('[APT v4.4] Qty clamped by position sizer: ' + qty + ' -> ' + _smClampedQty +
    ' (sector: ' + (prev._sm_sizer_sector || '?') + ', notional: $' + (prev._sm_sizer_notional || '?') + ')');
  qty = _smClampedQty;
}

if (price > 0) {
  let _finalCheckEquity = 100000;
  try {
    const _acctCheck = await this.helpers.httpRequest({
      method: 'GET', url: BASE + '/v2/account', headers: HDR, json: true
    });
    _finalCheckEquity = parseFloat(_acctCheck.equity || _acctCheck.portfolio_value || 100000);
  } catch (_) {}

  const _maxNotional = _finalCheckEquity * 0.10;
  const _proposedNotional = price * qty;
  if (_proposedNotional > _maxNotional) {
    const _oldQty = qty;
    qty = Math.max(1, Math.floor(_maxNotional / price));
    console.log('[APT v4.4] FINAL GUARD: notional $' + _proposedNotional.toFixed(0) +
      ' exceeds 10% of $' + _finalCheckEquity.toFixed(0) + ' equity. Clamped: ' + _oldQty + ' -> ' + qty);
  }
}
// ─────────────────────────────────────────────────────────────────────────────

const stopPrice = isLong ? r2(price - atr * SL_MULT) : r2(price + atr * SL_MULT);

const slipBuffer = r2(Math.max(0.10, price * (vol ? 0.002 : 0.001)));
const stopLimit  = isLong ? r2(stopPrice - slipBuffer) : r2(stopPrice + slipBuffer);

const tpPrice = isLong
  ? r2(price + atr * (vol ? 2.0 : 3.0))
  : r2(price - atr * (vol ? 2.0 : 3.0));

async function retry(fn, n = 2, ms = 800) {
  for (let i = 0; i <= n; i++) {
    try { return await fn(); }
    catch (e) {
      if (i === n) throw e;
      await new Promise(r => setTimeout(r, ms * Math.pow(2, i)));
    }
  }
}

// ── H-2 FIX: Fetch NBBO quote for limit order pricing ──────────────────────
// Replaces blind market orders with informed limit orders.
// For buys:  limit = ask + 1 tick (crosses spread, guarantees fill, caps slippage)
// For sells: limit = bid - 1 tick
// Wide spread guard: if spread > 0.5% of mid → use mid ± 1 tick instead
// Fallback: market order if quote unavailable (safety > optimization)
let entryType = 'market';   // default fallback
let entryLimit = null;       // set if we get a valid quote
let quoteData = null;

try {
  const quoteResp = await this.helpers.httpRequest({
    method: 'GET',
    url: DATA_BASE + '/stocks/' + ticker + '/quotes/latest',
    headers: {
      'APCA-API-KEY-ID':     ALPACA_KEY,
      'APCA-API-SECRET-KEY': ALPACA_SEC,
    },
    json: true,
    timeout: 5000,
  });

  const q = quoteResp.quote || quoteResp;
  const bid = parseFloat(q.bp || q.bid_price || 0);
  const ask = parseFloat(q.ap || q.ask_price || 0);
  const bidSize = parseInt(q.bs || q.bid_size || 0);
  const askSize = parseInt(q.as || q.ask_size || 0);

  if (bid > 0 && ask > 0 && ask >= bid) {
    const spread = ask - bid;
    const mid = (bid + ask) / 2;
    const spreadPct = spread / mid;
    const isBuy = side === 'buy';

    if (spreadPct > SPREAD_WARN_PCT) {
      // Wide spread — cap at midpoint + 1 tick to limit adverse selection
      entryLimit = isBuy ? r2(mid + TICK) : r2(mid - TICK);
      console.log('[APT v4.4] WIDE SPREAD ' + ticker + ': bid=$' + bid + ' ask=$' + ask +
        ' spread=' + (spreadPct * 100).toFixed(3) + '% → limit=$' + entryLimit + ' (mid±tick)');
    } else {
      // Normal spread — cross it aggressively to guarantee fill
      entryLimit = isBuy ? r2(ask + TICK) : r2(bid - TICK);
      console.log('[APT v4.4] QUOTE ' + ticker + ': bid=$' + bid + ' ask=$' + ask +
        ' spread=$' + spread.toFixed(4) + ' → limit=$' + entryLimit);
    }

    entryType = 'limit';
    quoteData = { bid, ask, bidSize, askSize, spread: r2(spread), mid: r2(mid), spreadPct: r2(spreadPct * 100), wideSpread: spreadPct > SPREAD_WARN_PCT };
  } else {
    console.warn('[APT v4.4] Invalid quote for ' + ticker + ': bid=' + bid + ' ask=' + ask + ' → market fallback');
  }
} catch (quoteErr) {
  console.warn('[APT v4.4] Quote fetch failed for ' + ticker + ': ' + quoteErr.message + ' → market fallback');
}
// ─────────────────────────────────────────────────────────────────────────────

let entryResp;

if (TRAIL_PCT) {
  // ── Volatile path: limit entry + trailing stop ─────────────────────────────
  // v4.4: limit order with IOC TIF → if IOC cancels, immediate market fallback
  // IOC fills what it can immediately, cancels the rest. For full-qty fills this
  // is equivalent to a market order but with a price ceiling.
  const entryBody = {
    symbol: ticker,
    qty: String(qty),
    side,
    type: entryType,
    time_in_force: entryType === 'limit' ? 'ioc' : 'gtc',
  };
  if (entryType === 'limit' && entryLimit) {
    entryBody.limit_price = String(entryLimit);
  }

  try {
    entryResp = await retry(() => this.helpers.httpRequest({
      method: 'POST', url: BASE + '/v2/orders', headers: HDR, json: true,
      body: JSON.stringify(entryBody)
    }));
  } catch (err) {
    console.error('[APT v4.4] Entry FAILED:', err.message);
    return [{ json: { ...prev, alpaca_status: 'ERROR', alpaca_error: err.message } }];
  }

  // v4.4: Check if IOC was immediately cancelled (no fill) → fallback to market
  const entryStatus = (entryResp?.status || '').toLowerCase();
  if (entryType === 'limit' && (entryStatus === 'canceled' || entryStatus === 'cancelled' || entryStatus === 'expired')) {
    console.log('[APT v4.4] IOC limit cancelled/expired for ' + ticker + ' → market fallback');
    try {
      entryResp = await retry(() => this.helpers.httpRequest({
        method: 'POST', url: BASE + '/v2/orders', headers: HDR, json: true,
        body: JSON.stringify({ symbol: ticker, qty: String(qty), side, type: 'market', time_in_force: 'gtc' })
      }));
      entryType = 'market';
      console.log('[APT v4.4] Market fallback succeeded for ' + ticker);
    } catch (fbErr) {
      console.error('[APT v4.4] Market fallback FAILED:', fbErr.message);
      return [{ json: { ...prev, alpaca_status: 'ERROR', alpaca_error: 'IOC+market both failed: ' + fbErr.message } }];
    }
  }

  const entryId = entryResp?.id;
  console.log(`[APT v4.4] VOL Entry: ${ticker} ${side} qty=${qty} type=${entryType} limit=$${entryLimit || 'N/A'} id=${entryId}`);

  await new Promise(r => setTimeout(r, 1200));

  let slId = null;
  try {
    const sl = await retry(() => this.helpers.httpRequest({
      method: 'POST', url: BASE + '/v2/orders', headers: HDR, json: true,
      body: JSON.stringify({
        symbol: ticker, qty: String(qty), side: closeSide,
        type: 'trailing_stop', trail_percent: TRAIL_PCT, time_in_force: 'gtc'
      })
    }));
    slId = sl?.id;
    console.log(`[APT v4.4] VOL Trail stop: ${ticker} trail=${TRAIL_PCT}% id=${slId}`);
  } catch (e) { console.error('[APT v4.4] Trail stop FAILED:', e.message); }

  const state = $getWorkflowStaticData('global');
  if (!state._bracketOrders) state._bracketOrders = {};
  state._bracketOrders[ticker] = {
    entryId, slId, tpId: null, isVolatile: true, side, qty,
    entryPrice: price, stopPrice: 'trail:' + TRAIL_PCT + '%', tpPrice: null,
    attachedAt: new Date().toISOString(), bracketType: 'trailing'
  };

  return [{ json: {
    ...prev,
    alpaca_status:      entryResp?.status || 'submitted',
    alpaca_entry_id:    entryId,
    alpaca_sl_id:       slId,
    alpaca_tp_id:       null,
    alpaca_stop_price:  'trail:' + TRAIL_PCT + '%',
    alpaca_tp_price:    null,
    alpaca_is_volatile: true,
    alpaca_atr_used:    atr,
    alpaca_bracket_v:   '4.4',
    alpaca_entry_type:  entryType,
    alpaca_limit_price: entryLimit,
    alpaca_quote:       quoteData,
    alpaca_sizer_sector: prev._sm_sizer_sector || 'N/A',
    alpaca_sizer_pct:    prev._sm_sizer_pct_of_equity || 0
  }}];

} else {
  // ── Standard path: bracket order with LIMIT entry (not market) ─────────────
  // v4.4: entry type changed from 'market' to 'limit' with limit_price from NBBO.
  // Bracket orders require TIF='gtc' or 'day' — IOC is not compatible.
  // Using 'gtc' to match existing behavior.
  const bracketBody = {
    symbol:          ticker,
    qty:             String(qty),
    side,
    type:            entryType,
    time_in_force:   'gtc',
    order_class:     'bracket',
    stop_loss: {
      stop_price:  String(stopPrice),
      limit_price: String(stopLimit)
    },
    take_profit: {
      limit_price: String(tpPrice)
    }
  };
  if (entryType === 'limit' && entryLimit) {
    bracketBody.limit_price = String(entryLimit);
  }

  try {
    entryResp = await retry(() => this.helpers.httpRequest({
      method: 'POST', url: BASE + '/v2/orders', headers: HDR, json: true,
      body: JSON.stringify(bracketBody)
    }));
  } catch (err) {
    // v4.4: If limit bracket fails, try market bracket as fallback
    if (entryType === 'limit') {
      console.warn('[APT v4.4] Limit bracket failed for ' + ticker + ': ' + err.message + ' → trying market bracket');
      bracketBody.type = 'market';
      delete bracketBody.limit_price;
      try {
        entryResp = await retry(() => this.helpers.httpRequest({
          method: 'POST', url: BASE + '/v2/orders', headers: HDR, json: true,
          body: JSON.stringify(bracketBody)
        }));
        entryType = 'market';
      } catch (fbErr) {
        console.error('[APT v4.4] Market bracket fallback FAILED:', fbErr.message);
        return [{ json: { ...prev, alpaca_status: 'ERROR', alpaca_error: fbErr.message } }];
      }
    } else {
      console.error('[APT v4.4] Bracket entry FAILED:', err.message);
      return [{ json: { ...prev, alpaca_status: 'ERROR', alpaca_error: err.message } }];
    }
  }

  const entryId = entryResp?.id;
  const legs    = entryResp?.legs || [];
  const slLeg   = legs.find(l => l.type === 'stop_limit' || l.type === 'stop');
  const tpLeg   = legs.find(l => l.type === 'limit');
  const slId    = slLeg?.id || null;
  const tpId    = tpLeg?.id || null;

  console.log(`[APT v4.4] Bracket: ${ticker} ${side} qty=${qty} type=${entryType} limit=$${entryLimit || 'N/A'} stop=$${stopPrice}(buf=$${slipBuffer}) tp=$${tpPrice} | entryId=${entryId} slId=${slId} tpId=${tpId}`);

  const state = $getWorkflowStaticData('global');
  if (!state._bracketOrders) state._bracketOrders = {};
  state._bracketOrders[ticker] = {
    entryId, slId, tpId, isVolatile: false, side, qty,
    entryPrice: price, stopPrice, stopLimit, tpPrice, slipBuffer,
    attachedAt: new Date().toISOString(), bracketType: 'native_oco'
  };

  return [{ json: {
    ...prev,
    alpaca_status:      entryResp?.status || 'submitted',
    alpaca_entry_id:    entryId,
    alpaca_sl_id:       slId,
    alpaca_tp_id:       tpId,
    alpaca_stop_price:  stopPrice,
    alpaca_stop_limit:  stopLimit,
    alpaca_slip_buffer: slipBuffer,
    alpaca_tp_price:    tpPrice,
    alpaca_is_volatile: false,
    alpaca_atr_used:    atr,
    alpaca_bracket_v:   '4.4',
    alpaca_entry_type:  entryType,
    alpaca_limit_price: entryLimit,
    alpaca_quote:       quoteData,
    alpaca_sizer_sector: prev._sm_sizer_sector || 'N/A',
    alpaca_sizer_pct:    prev._sm_sizer_pct_of_equity || 0
  }}];
}

