  });
} catch (e) {
  grokError = e.message;
  console.error('[GROK] API call failed:', e.message);
}

// Extract ONLY the inner analysis content — not the whole API response object
// sanitizeMD in Format Telegram converts [ → ( and _ → space, so never pass raw JSON blobs
let choicesContent;
if (grokResponse) {
  if (grokResponse.choices && grokResponse.choices[0] && grokResponse.choices[0].message && grokResponse.choices[0].message.content) {
    choicesContent = grokResponse.choices[0].message.content; // just the analysis JSON string
  } else if (typeof grokResponse === 'string') {
    choicesContent = grokResponse;
  } else {
    choicesContent = JSON.stringify(grokResponse);
  }
} else {
  choicesContent = JSON.stringify({ signal_verdict: "WEAK", confidence: 5, trade_action: "HOLD", error: grokError || "API unavailable" });
}

return [{
  json: {
    ...item,
    choices: [{ message: { content: choicesContent } }],
    _grok_called: true,
    _grok_error: grokError || null
  }
}];

// Rate Limit Throttle v2 — Per-ticker rate limiting for Google Sheets API
// Limits: max 1 write per ticker per 60 seconds
const state = $getWorkflowStaticData('global');
if (!state._sheetThrottle) state._sheetThrottle = {};

const items = $input.all();
const results = [];
const now = Date.now();
const MIN_INTERVAL_MS = 60000; // 1 write per ticker per 60 seconds

for (const item of items) {
  const ticker = item.json.ticker || item.json._shadow_ticker || 'UNKNOWN';
  const lastWrite = state._sheetThrottle[ticker] || 0;

  if (now - lastWrite >= MIN_INTERVAL_MS) {
    state._sheetThrottle[ticker] = now;
    results.push(item);
  } else {
    console.log('[THROTTLE] Skipped ' + ticker + ' — last write ' + Math.round((now - lastWrite) / 1000) + 's ago');
  }
}

// Prune throttle state for tickers not seen in 24h
const PRUNE_MS = 24 * 60 * 60 * 1000;
for (const key of Object.keys(state._sheetThrottle)) {
  if (now - state._sheetThrottle[key] > PRUNE_MS) {
    delete state._sheetThrottle[key];
  }
}

// Always pass at least 1 item (n8n requires it) — use a 3s delay as fallback
if (results.length === 0) {
  await new Promise(r => setTimeout(r, 3000));
  return $input.all();
}

return results;

// GTC Position Re-Check v5.15
// Reads state._pendingGTCCloses, checks Alpaca for each pending ticker.
// If position is flat (404) → set re-entry cooldown and remove from pending.
// If still open → increment retryCount. Alert if max retries reached.

const state = $getWorkflowStaticData('global');

if (!state._pendingGTCCloses) state._pendingGTCCloses = {};
const pending = state._pendingGTCCloses;
const tickerList = Object.keys(pending);

if (tickerList.length === 0) {
  console.log('[GTC-CHECK v5.15] No pending GTC closes.');
  return [];
}

const ALPACA_KEY    = ($getWorkflowStaticData('global')._alpaca_key) || '${ALPACA_API_KEY}';
const ALPACA_SECRET = ($getWorkflowStaticData('global')._alpaca_secret) || '${ALPACA_SECRET_KEY}';
const ALPACA_BASE   = 'https://paper-api.alpaca.markets';
const MAX_RETRIES   = parseInt((state._config && state._config.gtcMaxRetries) || 2);
const COOLDOWN_HRS  = parseFloat((state._config && state._config.reEntryCooldownHours) || 24);

const nowMs      = Date.now();
const confirmed  = [];
const stillOpen  = [];
const maxedOut   = [];

console.log('[GTC-CHECK v5.15] Checking ' + tickerList.length + ' pending close(s): ' + tickerList.join(', '));

for (const ticker of tickerList) {
  const entry = pending[ticker];

  try {
    let isFlat = false;

    try {
      await this.helpers.httpRequest({
        method: 'GET',
        url: ALPACA_BASE + '/v2/positions/' + ticker,
        headers: {
          'APCA-API-KEY-ID': ALPACA_KEY,
          'APCA-API-SECRET-KEY': ALPACA_SECRET
        },
        json: true
      });
      // 200 = position still open
      isFlat = false;
      console.log('[GTC-CHECK v5.15] ' + ticker + ': still OPEN');
    } catch (posErr) {
      const msg = posErr.message || '';
      if (msg.includes('404') || msg.includes('not found') || msg.includes('does not exist')) {
        isFlat = true;
        console.log('[GTC-CHECK v5.15] ' + ticker + ': FLAT — position confirmed closed');
      } else {
        throw posErr;
      }
    }

    if (isFlat) {
      // Set re-entry cooldown — deferred from kill time to now
      if (!state._reEntryCooldown) state._reEntryCooldown = {};
      state._reEntryCooldown[ticker] = nowMs;
      delete state._pendingGTCCloses[ticker];
      confirmed.push(ticker);

      // Post-close confirmation alert
      const _etTime = new Date(nowMs).toLocaleTimeString('en-US', {
        timeZone: 'America/New_York', hour: 'numeric', minute: '2-digit', hour12: true
      });
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: 6648680513,
            text: 'GTC confirmed closed: ' + ticker + ' at ' + _etTime + '. Re-entry cooldown now active (' + COOLDOWN_HRS + 'h).'
          }),
          json: true
        });
      } catch (_tgErr) { /* silent */ }
      console.log('[GTC-CHECK v5.15] ' + ticker + ': cooldown set (' + COOLDOWN_HRS + 'h re-entry block)');
    } else {
      entry.retryCount = (entry.retryCount || 0) + 1;
      state._pendingGTCCloses[ticker] = entry;

      if (entry.retryCount >= MAX_RETRIES) {
        maxedOut.push(ticker);
        console.log('[GTC-CHECK v5.15] WARNING: ' + ticker + ' still open after ' + MAX_RETRIES + ' polls — manual check needed');
      } else {
        stillOpen.push(ticker);
      }
    }

  } catch (err) {
    console.log('[GTC-CHECK v5.15] Error on ' + ticker + ': ' + err.message);
    stillOpen.push(ticker);
  }
}

// Send Telegram summary only if there is something actionable
if (confirmed.length > 0 || maxedOut.length > 0) {
  const lines = ['✅ GTC Re-Check v5.15'];
  if (confirmed.length > 0)
    lines.push('Closed + cooldown set: ' + confirmed.join(', '));
  if (maxedOut.length > 0)
    lines.push('WARNING — still open after ' + MAX_RETRIES + ' polls: ' + maxedOut.join(', ') +
      '. Check Alpaca manually — close order may have failed.');
  if (stillOpen.length > 0)
    lines.push('Still pending (retry): ' + stillOpen.join(', '));

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id: 6648680513, text: lines.join('\n') }),
      json: true
    });
  } catch (_tgErr) { /* silent */ }
}

return [{ json: { confirmed, stillOpen, maxedOut, totalPending: Object.keys(state._pendingGTCCloses).length } }];

// Indicator Enrichment v1 — Backfills missing technical indicators from Polygon
// Runs after Gap News Detector, before Signal State Machine
// Only fetches what's missing — zero overhead for fully-populated TradingView alerts

// ── Stable signal timestamp — set ONCE at pipeline entry, preserved by all
// downstream nodes via {...prev}. Log Alert to Sheet uses this as the
// appendOrUpdate row key so VC/Grok enrichment updates the SAME row.
const _rawItem = $input.first().json;
const item = {
  ..._rawItem,
  _signal_timestamp: _rawItem._signal_timestamp || new Date().toISOString()
};
const POLYGON_KEY = 'LxG0VrVzcQYEtWDfg8d6G49iapiC4Ec_';

// Determine if enrichment is needed
const needsRsi    = !item.rsi    || item.rsi    === 'N/A' || item.rsi    === 0 || item.rsi    === '0';
const needsMacd   = !item.macd_hist || item.macd_hist === 'N/A' || item.macd_hist === 0 || item.macd_hist === '0';
const needsSma50  = !item.sma50  || item.sma50  === 'N/A' || item.sma50  === 0 || item.sma50  === '0';
const needsEma200 = !item.ema200 || item.ema200 === 'N/A' || item.ema200 === 0 || item.ema200 === '0';
const needsVwap   = !item.vwap   || item.vwap   === 'N/A' || item.vwap   === 0 || item.vwap   === '0';

const ticker = item.ticker;
if (!ticker || ticker === 'UNKNOWN') return [{ json: item }];

// If everything is present, pass through immediately — no API calls
if (!needsRsi && !needsMacd && !needsSma50 && !needsEma200 && !needsVwap) {
  console.log('[ENRICH] All indicators present for', ticker, '— pass-through');
  return [{ json: item }];
}

// Determine timespan for RSI/MACD based on signal timeframe
const tf = (item.timeframe || '').toString().toUpperCase();
const isScalp = ['1','1M','3','3M','5','5M','15','15M'].includes(tf);
const indTimespan = isScalp ? 'minute' : 'day';

const enriched = { ...item };

// Helper: safe fetch
async function safeFetch(url) {
  try {
    return await this.helpers.httpRequest({ method: 'GET', url });
  } catch (e) {
    console.error('[ENRICH] Fetch error:', e.message);
    return null;
  }
}

// Fetch RSI (14)
if (needsRsi) {
  const url = `https://api.polygon.io/v1/indicators/rsi/${ticker}?timespan=${indTimespan}&adjusted=true&window=14&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.rsi = parseFloat(v).toFixed(2);
  console.log('[ENRICH] RSI', ticker, '=', enriched.rsi);
}

// Fetch MACD histogram (12/26/9)
if (needsMacd) {
  const url = `https://api.polygon.io/v1/indicators/macd/${ticker}?timespan=${indTimespan}&adjusted=true&short_window=12&long_window=26&signal_window=9&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.histogram;
  if (v !== undefined) enriched.macd_hist = parseFloat(v).toFixed(4);
  console.log('[ENRICH] MACD', ticker, '=', enriched.macd_hist);
}

// Fetch SMA50 (daily)
if (needsSma50) {
  const url = `https://api.polygon.io/v1/indicators/sma/${ticker}?timespan=day&adjusted=true&window=50&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.sma50 = parseFloat(v).toFixed(2);
  console.log('[ENRICH] SMA50', ticker, '=', enriched.sma50);
}

// Fetch EMA200 (daily)
if (needsEma200) {
  const url = `https://api.polygon.io/v1/indicators/ema/${ticker}?timespan=day&adjusted=true&window=200&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.ema200 = parseFloat(v).toFixed(2);
  console.log('[ENRICH] EMA200', ticker, '=', enriched.ema200);
}

// Fetch VWAP (from daily aggregate bar — field is 'vw' in Polygon aggs)
if (needsVwap) {
  const today = new Date().toISOString().split('T')[0];
  const aggUrl = `https://api.polygon.io/v2/aggs/ticker/${ticker}/range/1/day/${today}/${today}?adjusted=true&apiKey=${POLYGON_KEY}`;
  const aggData = await safeFetch.call(this, aggUrl);
  let v = aggData?.results?.[0]?.vw;
  // Fallback: try snapshot endpoint if agg not available yet (pre-market)
  if (!v || v === 0) {
    const snapUrl = `https://api.polygon.io/v2/snapshot/locale/us/markets/stocks/tickers/${ticker}?apiKey=${POLYGON_KEY}`;
    const snapData = await safeFetch.call(this, snapUrl);
    v = snapData?.ticker?.day?.vwap || snapData?.ticker?.min?.av;
  }
  if (v !== undefined && v !== 0) enriched.vwap = parseFloat(v).toFixed(2);
  console.log('[ENRICH] VWAP', ticker, '=', enriched.vwap);
}

enriched._enriched = true;
enriched._enriched_fields = ['rsi','macd','sma50','ema200','vwap'].filter((f,i) => [
  needsRsi && enriched.rsi !== item.rsi,
  needsMacd && enriched.macd_hist !== item.macd_hist,
  needsSma50 && enriched.sma50 !== item.sma50,
  needsEma200 && enriched.ema200 !== item.ema200,
  needsVwap && enriched.vwap !== item.vwap
][i]).join(',');

console.log('[ENRICH] Done for', ticker, '— filled:', enriched._enriched_fields || 'none');
return [{ json: enriched }];

// ═══════════════════════════════════════════════════════════════════════════
// UNIFIED CHANNEL GATE v1.0 — Single Telegram notification decision point
// ═══════════════════════════════════════════════════════════════════════════
// This node is the ONLY gate before Send to Channel. It enforces:
//   1. alpaca_status must confirm a real trade was placed
//   2. Message must not be empty/undefined
//   3. 60-second per-ticker dedup to prevent duplicate messages
//   4. Test mode signals are silently blocked
//
// ALL paths to Send to Channel MUST go through this gate.
// If you add a new notification path, wire it through here.

const prev = $input.first().json;
const message = prev.message || '';

// Gate 1: Message must exist and not be "undefined"
if (!message || message === 'undefined' || message.trim() === '') {
  console.log('[CHAN GATE v1] BLOCKED — empty/undefined message');
  return [];
}

// Gate 2: Test mode check
const _isTest = (prev.test_mode === true || prev.test === true || prev.test === 'true');
if (_isTest) {
  console.log('[CHAN GATE v1] BLOCKED — test signal');
  return [];
}

// Gate 3: Global dedup — 60-second per-ticker cooldown
const _state = $getWorkflowStaticData('global');
if (!_state._chanGateDedup) _state._chanGateDedup = {};
const _ticker = prev.ticker || 'UNKNOWN';
const _dedupKey = _ticker + '_' + (prev.timeframe || '');
const _lastMs = _state._chanGateDedup[_dedupKey] || 0;
if (Date.now() - _lastMs < 60000) {
  console.log('[CHAN GATE v1] DEDUP — ' + _dedupKey + ' sent within 60s, suppressing');
  return [];
}
_state._chanGateDedup[_dedupKey] = Date.now();

// Prune old entries (>5 min)
for (const k of Object.keys(_state._chanGateDedup)) {
  if (Date.now() - _state._chanGateDedup[k] > 300000) delete _state._chanGateDedup[k];
}

// All gates passed — forward to Send to Channel
console.log('[CHAN GATE v1] APPROVED — ' + _ticker + ' message length=' + message.length);
return [{ json: prev }];

